export const WISDOM = [
// ── LOVE (60) ────────────────────────────────────────────────────────────────
{id:'l1',category:'love',type:'quote',text:'Love is not a feeling you fall into. It is a choice you make, rebuild, and renew every single day.',author:'Loving Better'},
{id:'l2',category:'love',type:'advice',text:'The love that survives Tuesday is worth more than the love that arrived on Saturday. Anyone can feel love when everything is going well. It takes something deeper to choose it when nothing is.',author:'Loving Better'},
{id:'l3',category:'love',type:'spark',text:'Love today like the version of you that you most want to become.'},
{id:'l4',category:'love',type:'quote',text:'Real love does not erase your past. It holds it with you and builds something new anyway.',author:'Loving Better'},
{id:'l5',category:'love',type:'advice',text:'Think of your relationship like a bank account. Every act of connection is a deposit. Every dismissal, every broken promise, every avoided conversation is a withdrawal. Check your balance today.',author:'Loving Better'},
{id:'l6',category:'love',type:'spark',text:'The goal is not a perfect partner. It is a real one.'},
{id:'l7',category:'love',type:'quote',text:'To love someone fully is to know them fully -- not the curated version but the 3am version. That is the person who needs to be loved.',author:'Loving Better'},
{id:'l8',category:'love',type:'advice',text:'Most couples do not fall out of love. They fall out of attention. Love stays. Attentiveness must be maintained. Pay attention to the person you chose.',author:'Loving Better'},
{id:'l9',category:'love',type:'spark',text:'Being in the same room is not the same as being present.'},
{id:'l10',category:'love',type:'quote',text:'A relationship is not a 50/50 deal. Some days you carry 80% and they carry 20. The goal is not fairness in every moment -- it is faithfulness across the long arc.',author:'Loving Better'},
{id:'l11',category:'love',type:'advice',text:'Before you decide that love is not enough, ask: have I been expressing love in the form my partner can actually receive? Love that does not land is not the same as love that does not exist.',author:'Loving Better'},
{id:'l12',category:'love',type:'spark',text:'Love is a verb. Today, make it active.'},
{id:'l13',category:'love',type:'quote',text:'The couples who make it are not the ones without problems. They are the ones who decided the person across from them was worth the work.',author:'Loving Better'},
{id:'l14',category:'love',type:'advice',text:'Love requires translation. What you feel inside must be expressed in a form your partner can receive. Feeling it is not enough. Find the form.',author:'Loving Better'},
{id:'l15',category:'love',type:'spark',text:'Choose them again today. That is what love looks like on an ordinary Wednesday.'},
{id:'l16',category:'love',type:'advice',text:'Love without safety is not love -- it is performance. Both people must feel safe enough to be fully known. Build the safety first.',author:'Loving Better'},
{id:'l17',category:'love',type:'quote',text:'You do not find the right person. You become someone capable of loving the right person.',author:'Loving Better'},
{id:'l18',category:'love',type:'spark',text:'Appreciation is a form of love. Name something you appreciate about them -- today, out loud.'},
{id:'l19',category:'love',type:'advice',text:'Love that never costs you anything has never really been tested. The moments that test it are also the moments that prove it.',author:'Loving Better'},
{id:'l20',category:'love',type:'quote',text:'The best thing you can do for your relationship is to keep becoming a better version of yourself.',author:'Loving Better'},
{id:'l21',category:'love',type:'spark',text:'One compliment. Specific. True. Today.'},
{id:'l22',category:'love',type:'advice',text:'Familiarity is the quiet thief of love. It makes you stop seeing the person you chose. Make a practice of seeing them fresh -- as if for the first time.',author:'Loving Better'},
{id:'l23',category:'love',type:'quote',text:'Love is not something you have. It is something you practise.',author:'Loving Better'},
{id:'l24',category:'love',type:'spark',text:'The relationship you want is built in the minutes, not the milestones.'},
{id:'l25',category:'love',type:'advice',text:'Neglect is not dramatic. It happens in the small daily choices to be elsewhere -- mentally, emotionally, attentionally. It is the most common way love erodes.',author:'Loving Better'},
{id:'l26',category:'love',type:'quote',text:'Every time you choose to stay in the room when it is hard, you are making a deposit into the relationship that compounds over time.',author:'Loving Better'},
{id:'l27',category:'love',type:'spark',text:'Touch them today -- not from desire, from warmth.'},
{id:'l28',category:'love',type:'advice',text:'There is a season in every relationship where you must choose: will I let what is difficult define us, or will I let what is possible define us? That choice is always available.',author:'Loving Better'},
{id:'l29',category:'love',type:'quote',text:'Love that has survived difficulty is love that knows what it is made of.',author:'Loving Better'},
{id:'l30',category:'love',type:'spark',text:'Say "I love you" slowly today. Make it land.'},
{id:'l31',category:'love',type:'advice',text:'Contempt is the most corrosive thing in a relationship. More than conflict. More than silence. When you feel the impulse to belittle, stop. Go back to the wound underneath.',author:'Loving Better'},
{id:'l32',category:'love',type:'quote',text:'You cannot pour from an empty vessel. Loving yourself is not selfishness -- it is preparation.',author:'Loving Better'},
{id:'l33',category:'love',type:'spark',text:'What would this relationship look like if both of you acted at your best today? Do that.'},
{id:'l34',category:'love',type:'advice',text:'Your partner cannot read your mind. Give them the information they need to love you well.',author:'Loving Better'},
{id:'l35',category:'love',type:'quote',text:'The love you are building is not the love you began with. It is harder and more real and more worth having.',author:'Loving Better'},
{id:'l36',category:'love',type:'spark',text:'Laughter is oxygen for a relationship. Find something to laugh about together today.'},
{id:'l37',category:'love',type:'advice',text:'Love is not proven in grand moments. It is proven in the ten thousand small moments -- in the greeting when they walk in, in the way you listen when they are talking, in what you do when they need you and you are tired.',author:'Loving Better'},
{id:'l38',category:'love',type:'quote',text:'The relationship you have is not the relationship you are stuck with. It is the relationship you are building -- right now.',author:'Loving Better'},
{id:'l39',category:'love',type:'spark',text:'Remember why you chose them. Not the worst version. The version that made you choose.'},
{id:'l40',category:'love',type:'advice',text:'Curiosity about your partner is one of the most loving things you can maintain. When you stop being curious about who they are becoming, you stop seeing them.',author:'Loving Better'},
{id:'l41',category:'love',type:'quote',text:'Good relationships are not found. They are built. Brick by brick, day by day, choice by choice.',author:'Loving Better'},
{id:'l42',category:'love',type:'spark',text:'Ask them one question today that you genuinely do not know the answer to.'},
{id:'l43',category:'love',type:'advice',text:'When you argue, you are not fighting each other. You are fighting the problem together. The moment you make your partner the enemy, you both lose.',author:'Loving Better'},
{id:'l44',category:'love',type:'quote',text:'A partner who tells you hard truths loves you more than one who only tells you comfortable ones.',author:'Loving Better'},
{id:'l45',category:'love',type:'spark',text:'What is the most generous interpretation of what they did today? Choose that one.'},
{id:'l46',category:'love',type:'advice',text:'Make the repair. Not tomorrow. Not when you feel ready. Make it today, even if it is imperfect. An imperfect repair is worth infinitely more than a perfect silence.',author:'Loving Better'},
{id:'l47',category:'love',type:'quote',text:'Every season in a relationship teaches you something about the person you chose. Difficult seasons teach you the most.',author:'Loving Better'},
{id:'l48',category:'love',type:'spark',text:'Send a message today with no purpose other than: I thought of you.'},
{id:'l49',category:'love',type:'advice',text:'The opposite of love is not hate -- it is indifference. As long as there is feeling, there is something to work with.',author:'Loving Better'},
{id:'l50',category:'love',type:'quote',text:'Love is patient -- not just in principle, but in the specific practice of waiting for someone to grow.',author:'Loving Better'},
{id:'l51',category:'love',type:'spark',text:'Sit near them today just because you want to be near them.'},
{id:'l52',category:'love',type:'advice',text:'Before bed tonight: name one thing you are grateful for about the person beside you. Say it out loud. Do this every night for a month and watch what changes.',author:'Loving Better'},
{id:'l53',category:'love',type:'quote',text:'Comparison kills. Your relationship is its own unique thing -- tend it.',author:'Loving Better'},
{id:'l54',category:'love',type:'spark',text:'Love in a relationship is also a culture -- the accumulated set of daily choices about how you treat each other.'},
{id:'l55',category:'love',type:'quote',text:'You will grow old together if you choose to. Growing closer while you grow old is the project.',author:'Loving Better'},
{id:'l56',category:'love',type:'advice',text:'To be fully known and fully loved at the same time -- that is the deepest human longing. Work toward being a place where that is possible for your partner.',author:'Loving Better'},
{id:'l57',category:'love',type:'spark',text:'What is one thing you love about them that you have never told them? Tell them today.'},
{id:'l58',category:'love',type:'quote',text:'The relationship needs you at your best. Do one thing to get there first.',author:'Loving Better'},
{id:'l59',category:'love',type:'advice',text:'Love that is conditional on the other person\'s behaviour is not love -- it is a transaction. The unconditional part is the part that heals.',author:'Loving Better'},
{id:'l60',category:'love',type:'spark',text:'Choose each other again today. Consciously. Deliberately. Out loud if you can.'},
// ── COMMUNICATION (80) ───────────────────────────────────────────────────────
{id:'c1',category:'communication',type:'quote',text:'Avoidance is not kindness. It is a slow way of letting the relationship starve.',author:'Loving Better'},
{id:'c2',category:'communication',type:'advice',text:'The conversations you have been putting off are sitting between you, growing heavier every day. The cost of having them is discomfort. The cost of not having them is everything.',author:'Loving Better'},
{id:'c3',category:'communication',type:'spark',text:'Ask one real question today. Not about logistics. About their inner world.'},
{id:'c4',category:'communication',type:'advice',text:'Before you respond in a difficult conversation, repeat back what you heard. "What I\'m hearing you say is…" That one habit eliminates most fighting about what was actually said.',author:'Loving Better'},
{id:'c5',category:'communication',type:'quote',text:'The softest words reach the furthest. Safety is what makes truth land.',author:'Loving Better'},
{id:'c6',category:'communication',type:'spark',text:'"How are you really doing?" -- say those five words today and mean them.'},
{id:'c7',category:'communication',type:'advice',text:'When you feel the need to say twelve things at once, choose one. Say it clearly. Give it room to land. One thing heard moves a relationship forward more than twelve things dumped at once.',author:'Loving Better'},
{id:'c8',category:'communication',type:'quote',text:'Silence is not neutral. It communicates -- just not what you intend.',author:'Loving Better'},
{id:'c9',category:'communication',type:'spark',text:'The conversation you are most afraid to have is probably the one you most need to have.'},
{id:'c10',category:'communication',type:'advice',text:'Name the pause. If a conversation is getting too heated, say: "I need twenty minutes and I am coming back." A named pause with a commitment to return repairs. Unannounced silence damages.',author:'Loving Better'},
{id:'c11',category:'communication',type:'quote',text:'A person who never brings hard things up is not keeping the peace. They are mortgaging it.',author:'Loving Better'},
{id:'c12',category:'communication',type:'spark',text:'Speak from the wound, not the war. The wound invites connection. The war invites defense.'},
{id:'c13',category:'communication',type:'advice',text:'Most fights are not really about the thing they appear to be about. They are about the thing underneath -- the unmet need, the old wound, the fear that was never spoken. Learn to name the underneath.',author:'Loving Better'},
{id:'c14',category:'communication',type:'quote',text:'The truth does not lose its truth if it is spoken gently. A truth spoken harshly is often the only thing the other person hears.',author:'Loving Better'},
{id:'c15',category:'communication',type:'spark',text:'Say the difficult thing once it has been sitting for more than 24 hours. The window gets smaller the longer you wait.'},
{id:'c16',category:'communication',type:'advice',text:'Use "I" statements in hard conversations. "I felt invisible when…" lands completely differently from "You never notice me." Same feeling, different outcome.',author:'Loving Better'},
{id:'c17',category:'communication',type:'quote',text:'Communication is the circulatory system of a relationship. When it flows, everything is nourished. When it is blocked, parts begin to die.',author:'Loving Better'},
{id:'c18',category:'communication',type:'spark',text:'Before the day ends, share one thing from your inner world that you have not said yet.'},
{id:'c19',category:'communication',type:'advice',text:'Timing matters in difficult conversations. Neither person should be hungry, tired, or already stressed when something important needs to be said. Choose the moment -- or ask for one.',author:'Loving Better'},
{id:'c20',category:'communication',type:'quote',text:'Being defensive is not the same as being wrong. It is a signal that you feel unsafe. What would it take to feel safe enough to hear this?',author:'Loving Better'},
{id:'c21',category:'communication',type:'spark',text:'Listen to understand, not to respond. The other person can always tell the difference.'},
{id:'c22',category:'communication',type:'advice',text:'Repair the conversation that ended badly. Do not let it sit for days. Come back within 24 hours and say: "I want to try that again differently." This habit changes everything.',author:'Loving Better'},
{id:'c23',category:'communication',type:'quote',text:'Every unsaid thing becomes a brick in a wall neither of you planned to build.',author:'Loving Better'},
{id:'c24',category:'communication',type:'spark',text:'Listen to what they are not saying. Sometimes the most important message lives in the silence around the words.'},
{id:'c25',category:'communication',type:'advice',text:'Once a week, initiate a 15-minute check-in. Ask: what made you feel loved this week? What would you have liked more of? These questions, asked consistently, replace crisis conversations.',author:'Loving Better'},
{id:'c26',category:'communication',type:'quote',text:'The couples who communicate well are not the ones who never feel afraid to talk. They are the ones who talk anyway.',author:'Loving Better'},
{id:'c27',category:'communication',type:'spark',text:'Name the feeling before you explain the situation. "I felt scared when…" opens more doors than "What you did was…"'},
{id:'c28',category:'communication',type:'advice',text:'Do not use silence as punishment. Silence used as a tool of control is contempt in disguise. Name what you need: "I need time to process and I will come back."',author:'Loving Better'},
{id:'c29',category:'communication',type:'quote',text:'Vulnerability is not weakness. It is the prerequisite for genuine connection.',author:'Loving Better'},
{id:'c30',category:'communication',type:'spark',text:'Ask: "Is there anything I did this week that hurt you and you haven\'t told me yet?" Then listen without defending.'},
{id:'c31',category:'communication',type:'advice',text:'There is a version of honesty that is really just cruelty with a clear conscience. Honest communication is precise, kind, and aimed at connection -- not discharge. Check your aim before you speak.',author:'Loving Better'},
{id:'c32',category:'communication',type:'quote',text:'The goal of a hard conversation is not to win. It is to understand and be understood.',author:'Loving Better'},
{id:'c33',category:'communication',type:'spark',text:'After a conflict: "Are we okay?" Two words. Ask them.'},
{id:'c34',category:'communication',type:'advice',text:'Never say "you always" or "you never." These phrases close the other person down instantly and they stop hearing the actual point. Use specific, recent examples instead.',author:'Loving Better'},
{id:'c35',category:'communication',type:'quote',text:'What you say in anger cannot be unsaid. What you leave unsaid in silence becomes resentment. Find the middle.',author:'Loving Better'},
{id:'c36',category:'communication',type:'spark',text:'Tell them something you appreciate about them before you tell them something that bothers you.'},
{id:'c37',category:'communication',type:'advice',text:'End every hard conversation with a gesture of reconnection. Even if the issue is unresolved. A hug, a held hand, a prayer -- something that says: we are still us inside this difficulty.',author:'Loving Better'},
{id:'c38',category:'communication',type:'quote',text:'Conversations avoided do not disappear. They accumulate -- and eventually arrive all at once.',author:'Loving Better'},
{id:'c39',category:'communication',type:'spark',text:'Share one thing with your partner today that you have not shared with anyone else.'},
{id:'c40',category:'communication',type:'advice',text:'Do not bring up old things in a current argument unless the pattern is directly relevant. Fighting the current issue AND the last three is how both people end up feeling attacked.',author:'Loving Better'},
{id:'c41',category:'communication',type:'quote',text:'Being a safe person to talk to is one of the most powerful things you can be for someone you love.',author:'Loving Better'},
{id:'c42',category:'communication',type:'spark',text:'Ask: "What do you need from me right now?" and be willing to give the answer, not debate it.'},
{id:'c43',category:'communication',type:'advice',text:'Validate before you respond. "I understand why you feel that way" is not surrender. It is the act of making the other person feel heard before you offer your perspective.',author:'Loving Better'},
{id:'c44',category:'communication',type:'quote',text:'Curiosity in a hard conversation disarms it. Replace "that\'s not true" with "help me understand what you mean."',author:'Loving Better'},
{id:'c45',category:'communication',type:'spark',text:'Before bed: "Is there anything between us that needs to be cleared before we sleep?"'},
{id:'c46',category:'communication',type:'advice',text:'The morning after a fight matters as much as the fight itself. Do not let the next day begin as if nothing happened. Acknowledge it briefly: "Yesterday was hard. I love you. Let\'s do better today."',author:'Loving Better'},
{id:'c47',category:'communication',type:'quote',text:'Silence after conflict is not peace. It is the pause before the next eruption, if nothing is addressed.',author:'Loving Better'},
{id:'c48',category:'communication',type:'spark',text:'If you have been waiting for the right moment -- this is the right moment.'},
{id:'c49',category:'communication',type:'advice',text:'Learn the difference between processing and punishing. "I am processing and need quiet" is a need. "I am giving you silence" as control is a weapon. Communicate which one you are doing.',author:'Loving Better'},
{id:'c50',category:'communication',type:'quote',text:'Two people who can talk about anything are unstoppable. Build toward that.',author:'Loving Better'},
{id:'c51',category:'communication',type:'spark',text:'When they are talking, put down everything else. Full attention is a love language many people never give.'},
{id:'c52',category:'communication',type:'advice',text:'The 24-hour rule: if something bothers you, raise it within 24 hours or formally choose to release it. Carrying it silently for weeks and then raising it is unfair to both of you.',author:'Loving Better'},
{id:'c53',category:'communication',type:'quote',text:'Honesty without love is brutality. Love without honesty is flattery. Real communication is both.',author:'Loving Better'},
{id:'c54',category:'communication',type:'spark',text:'Name one thing you need today. Not a complaint -- a need. State it clearly.'},
{id:'c55',category:'communication',type:'advice',text:'Speaking your truth gently is not the same as softening the truth. It is choosing the form that gives the truth the best chance of being received.',author:'Loving Better'},
{id:'c56',category:'communication',type:'quote',text:'The person who raises the hard thing first is not the problem. They are the bravest person in the room.',author:'Loving Better'},
{id:'c57',category:'communication',type:'spark',text:'What have you been waiting to say? The waiting is costing you more than the saying.'},
{id:'c58',category:'communication',type:'advice',text:'When you interrupt someone in a hard conversation you are not just cutting off their words -- you are telling them that your response matters more than their expression. Wait until they are finished. Always.',author:'Loving Better'},
{id:'c59',category:'communication',type:'quote',text:'An apology that includes "but" is not an apology. It is a negotiation. Remove the "but."',author:'Loving Better'},
{id:'c60',category:'communication',type:'spark',text:'What is one thing you have been communicating through your behaviour that you have never said out loud?'},
{id:'c61',category:'communication',type:'advice',text:'After a good conversation -- the kind where you both feel heard and something shifted -- name it. Say: "That was a good conversation. I want more of those." Acknowledging what works trains both of you to do more of it.',author:'Loving Better'},
{id:'c62',category:'communication',type:'quote',text:'The thing beneath the complaint is always a need. When you hear a complaint, listen for the need.',author:'Loving Better'},
{id:'c63',category:'communication',type:'spark',text:'What tone of voice do you use most often with your partner? Would you use that tone with someone you were trying to impress?'},
{id:'c64',category:'communication',type:'advice',text:'When you do not know what to say in a hard moment, say that: "I do not know what to say right now, but I am not going anywhere." That sentence does more than any prepared response.',author:'Loving Better'},
{id:'c65',category:'communication',type:'quote',text:'You can be honest and still be kind. In fact, that is the only form of honesty worth practising in love.',author:'Loving Better'},
{id:'c66',category:'communication',type:'spark',text:'What is your partner\'s primary way of feeling heard? Are you using it?'},
{id:'c67',category:'communication',type:'advice',text:'Before a difficult conversation, ask yourself: what do I want to happen at the end of this? That answer changes how you begin it. If you want understanding, begin with curiosity. If you want resolution, begin with the specific thing.',author:'Loving Better'},
{id:'c68',category:'communication',type:'quote',text:'The couples who never fight are not the healthiest ones. The healthiest ones are the ones who fight and always come back.',author:'Loving Better'},
{id:'c69',category:'communication',type:'spark',text:'Say "I hear you" and mean it -- not as a phrase but as a commitment to actually having heard them.'},
{id:'c70',category:'communication',type:'advice',text:'Humour can be a bridge in difficult conversations or a way of avoiding them. Know which one you are using it for in any given moment.',author:'Loving Better'},
{id:'c71',category:'communication',type:'quote',text:'The conversation that feels too risky to have is usually the conversation that will bring you closest.',author:'Loving Better'},
{id:'c72',category:'communication',type:'spark',text:'One conversation at a time. One issue. Give it the space it deserves.'},
{id:'c73',category:'communication',type:'advice',text:'Let them finish the sentence. Not the sentence you predict they are going to say -- the sentence they are actually saying. They may surprise you.',author:'Loving Better'},
{id:'c74',category:'communication',type:'quote',text:'Communication is not just what you say. It is what you do not say, what you assume, what you avoid, and what your body communicates when your mouth is closed.',author:'Loving Better'},
{id:'c75',category:'communication',type:'spark',text:'What does your face do when they are talking? Is it the face of someone who wants to hear what they are saying?'},
{id:'c76',category:'communication',type:'advice',text:'Give your partner the gift of being surprising. Stop finishing their sentences, stop predicting their responses, stop relating to the story of them from three years ago. Ask. Listen. Be surprised.',author:'Loving Better'},
{id:'c77',category:'communication',type:'quote',text:'A relationship where both people feel heard is a relationship where both people can breathe.',author:'Loving Better'},
{id:'c78',category:'communication',type:'spark',text:'What is the best conversation you two have ever had? What made it that good? Try to create that again.'},
{id:'c79',category:'communication',type:'advice',text:'Do not let a week go by without asking your partner something you genuinely want to know about their inner world. Not logistics -- what they think, what they feel, what they dream about, what they fear.',author:'Loving Better'},
{id:'c80',category:'communication',type:'quote',text:'The most important conversation is the one you keep having -- the one about who you are to each other and who you are choosing to become.',author:'Loving Better'},
// ── TRUST (50) ───────────────────────────────────────────────────────────────
{id:'t1',category:'trust',type:'quote',text:'Trust is not rebuilt in a conversation. It is rebuilt in the accumulation of small, consistent, kept commitments over time.',author:'Loving Better'},
{id:'t2',category:'trust',type:'advice',text:'The gap between what you promised and what you did is where trust lives or dies. Close it not by making fewer promises but by keeping more of the ones you make.',author:'Loving Better'},
{id:'t3',category:'trust',type:'spark',text:'One promise, kept completely, today. Just one.'},
{id:'t4',category:'trust',type:'advice',text:'Trustworthiness is not a personality trait. It is a practice. You become reliable by doing the thing you said you would do, one more time, one more day.',author:'Loving Better'},
{id:'t5',category:'trust',type:'quote',text:'Insecurity in a relationship is often not a personal flaw. It is a reasonable response to inconsistency.',author:'Loving Better'},
{id:'t6',category:'trust',type:'spark',text:'When you slip on a commitment, go to your partner first. Do not wait to be caught.'},
{id:'t7',category:'trust',type:'advice',text:'Transparency is not about having no privacy. It is about not hiding the things your partner has a right to know. Is there anything you are concealing that is costing you closeness?',author:'Loving Better'},
{id:'t8',category:'trust',type:'quote',text:'A secure relationship is not one that has never been tested. It is one that has been tested and survived.',author:'Loving Better'},
{id:'t9',category:'trust',type:'spark',text:'Trust is built in 1000 small moments, not in one big gesture.'},
{id:'t10',category:'trust',type:'advice',text:'When you commit to change, be specific. Not "I will do better" -- but "I will do this specific thing by this specific time." Vague commitments dissolve. Specific ones can be kept.',author:'Loving Better'},
{id:'t11',category:'trust',type:'quote',text:'The question is not whether you can be trusted. The question is whether you will choose, over and over, to do the things that prove it.',author:'Loving Better'},
{id:'t12',category:'trust',type:'spark',text:'What did you say you would do that you have not done? Address it today.'},
{id:'t13',category:'trust',type:'advice',text:'Trust is also about predictability. Your partner needs to be able to predict how you will behave -- not because you are boring, but because consistency is what safety feels like.',author:'Loving Better'},
{id:'t14',category:'trust',type:'quote',text:'Integrity in a relationship means that who you are when your partner is watching is the same as who you are when they are not.',author:'Loving Better'},
{id:'t15',category:'trust',type:'spark',text:'Do the thing you said you would do. Not tomorrow. Today.'},
{id:'t16',category:'trust',type:'advice',text:'Every broken promise is a withdrawal from the trust account. But an acknowledged broken promise -- named specifically, with a genuine plan -- withdraws less than one quietly ignored.',author:'Loving Better'},
{id:'t17',category:'trust',type:'quote',text:'The deepest form of trust is knowing that the other person will tell you the truth even when it is hard for them to say.',author:'Loving Better'},
{id:'t18',category:'trust',type:'spark',text:'Be the same person in private that you are in public. Your partner needs consistency, not performance.'},
{id:'t19',category:'trust',type:'advice',text:'Make commitments that are small enough to actually keep. The goal is not to promise the most beautiful thing. It is to promise what you can deliver -- and then deliver it without fail.',author:'Loving Better'},
{id:'t20',category:'trust',type:'quote',text:'Earned trust is worth infinitely more than assumed trust.',author:'Loving Better'},
{id:'t21',category:'trust',type:'spark',text:'What does your partner most need to be able to rely on you for? Are you reliable in that area?'},
{id:'t22',category:'trust',type:'advice',text:'If you have broken trust, do not ask for instant forgiveness. Ask for the opportunity to demonstrate change over time. Then demonstrate it.',author:'Loving Better'},
{id:'t23',category:'trust',type:'quote',text:'A relationship without trust is a shell. It can look intact from the outside while everything real inside it is gone.',author:'Loving Better'},
{id:'t24',category:'trust',type:'spark',text:'Review your commitments from last week. How many were fully kept? Be honest.'},
{id:'t25',category:'trust',type:'advice',text:'Spontaneous follow-through is worth ten times as much as follow-through that only happens after a reminder. Show up before they have to ask.',author:'Loving Better'},
{id:'t26',category:'trust',type:'quote',text:'What you do when no one is checking is who you actually are. Make sure those two versions match.',author:'Loving Better'},
{id:'t27',category:'trust',type:'spark',text:'Consistency is not glamorous. It is everything.'},
{id:'t28',category:'trust',type:'advice',text:'Trust requires that both people tell the truth even when it is inconvenient. The truth withheld because "it will cause a problem" is exactly the truth that causes the bigger problem later.',author:'Loving Better'},
{id:'t29',category:'trust',type:'quote',text:'The most loving thing you can do is be someone your partner never has to wonder about.',author:'Loving Better'},
{id:'t30',category:'trust',type:'spark',text:'What one thing could you do this week that would make your partner feel more secure?'},
{id:'t31',category:'trust',type:'advice',text:'Trust your partner\'s perception of events even when it differs from yours. Two people can experience the same event differently and both be telling the truth. Believe their experience.',author:'Loving Better'},
{id:'t32',category:'trust',type:'quote',text:'When someone tells you something hurt them, the correct response is not "I did not mean it that way." The correct response is "I am sorry it landed that way. Tell me more."',author:'Loving Better'},
{id:'t33',category:'trust',type:'spark',text:'What is one area where you have been less than transparent? Begin to open that area.'},
{id:'t34',category:'trust',type:'advice',text:'Rebuilding trust is not linear. There will be good weeks and hard weeks. The hard weeks do not erase the progress. They are part of it.',author:'Loving Better'},
{id:'t35',category:'trust',type:'quote',text:'To be trustworthy is to be someone whose word is the same thing as their action.',author:'Loving Better'},
{id:'t36',category:'trust',type:'spark',text:'The person who goes first in vulnerability is often the one who makes the space safe enough for both.'},
{id:'t37',category:'trust',type:'advice',text:'Never share your partner\'s private vulnerabilities with other people. The things they tell you in the dark are sacred. Betraying them in conversation is one of the most damaging things you can do to trust.',author:'Loving Better'},
{id:'t38',category:'trust',type:'quote',text:'Trust is not given. It is grown -- through time, through consistency, through being the same person in all conditions.',author:'Loving Better'},
{id:'t39',category:'trust',type:'spark',text:'What would your partner say is the area where you are most reliable? What area would they name as the least consistent?'},
{id:'t40',category:'trust',type:'advice',text:'When you say "trust me" without giving your partner any specific reason to, you are asking for something you have not yet earned. Give them a reason. Then give them another one. Let the evidence accumulate.',author:'Loving Better'},
{id:'t41',category:'trust',type:'quote',text:'You become trustworthy one kept promise at a time. There is no shortcut.',author:'Loving Better'},
{id:'t42',category:'trust',type:'spark',text:'Name one area of your life you have been keeping separate from this relationship. Is that separation serving both of you?'},
{id:'t43',category:'trust',type:'advice',text:'Never make a promise during a reconciliation that you do not fully intend to keep in ordinary life. The emotion of reconciliation is temporary. The commitment must outlast it.',author:'Loving Better'},
{id:'t44',category:'trust',type:'quote',text:'Security in a relationship is not the absence of fear. It is the confidence that even if things get hard, the other person will stay.',author:'Loving Better'},
{id:'t45',category:'trust',type:'spark',text:'What do you need to stop doing that is eroding trust? Name it. Stop it.'},
{id:'t46',category:'trust',type:'advice',text:'The fastest way to rebuild trust after breaking it is this: acknowledge what you did specifically, without minimising or explaining, and then ask what the other person needs from you going forward.',author:'Loving Better'},
{id:'t47',category:'trust',type:'quote',text:'A partner who follows through on the small things is telling you something important: they pay attention to what matters to you.',author:'Loving Better'},
{id:'t48',category:'trust',type:'spark',text:'Trust is built in the quiet moments when no one is watching. What are you building in those moments?'},
{id:'t49',category:'trust',type:'advice',text:'When trust has been damaged, the worst thing the hurt party can do is pretend it has not been. Name it. Acknowledge it. Give it the weight it deserves. Then decide together what rebuilding looks like.',author:'Loving Better'},
{id:'t50',category:'trust',type:'quote',text:'Be someone your future self will be proud of having been in this relationship.',author:'Loving Better'},
// ── HEALING (50) ─────────────────────────────────────────────────────────────
{id:'h1',category:'healing',type:'advice',text:'Your parents\' marriage is not your destiny. It is a warning. You can see the pattern, name it, grieve it, and choose differently.',author:'Loving Better'},
{id:'h2',category:'healing',type:'quote',text:'Forgiveness is not saying what happened was fine. It is deciding that the hurt will not have the final word.',author:'Loving Better'},
{id:'h3',category:'healing',type:'spark',text:'Healing is not the absence of pain. It is the presence of peace even while the pain is there.'},
{id:'h4',category:'healing',type:'advice',text:'Unhealed wounds wound others. The pain you carry from before this relationship shows up in it. Pursue your own healing as an act of love for your partner.',author:'Loving Better'},
{id:'h5',category:'healing',type:'quote',text:'You cannot carry the past and build the future at the same time. At some point you have to decide which one matters more.',author:'Loving Better'},
{id:'h6',category:'healing',type:'spark',text:'Name one thing you are still holding from the past. Even just to yourself.'},
{id:'h7',category:'healing',type:'advice',text:'Resentment is what happens when pain is never processed. It is not your fault that it built up. But it is your responsibility to address it -- by naming things as they happen while they are still small.',author:'Loving Better'},
{id:'h8',category:'healing',type:'quote',text:'Healing in a relationship is not linear. You will have weeks that feel like progress and weeks that feel like regression. Both are part of the same path.',author:'Loving Better'},
{id:'h9',category:'healing',type:'spark',text:'The wound underneath the anger is the thing worth addressing. Find it.'},
{id:'h10',category:'healing',type:'advice',text:'There is a difference between carrying your history and being imprisoned by it. Your past shaped you. It does not have to sentence you.',author:'Loving Better'},
{id:'h11',category:'healing',type:'quote',text:'Repair after a rupture matters more than the rupture itself. The couples who make it are the ones who come back.',author:'Loving Better'},
{id:'h12',category:'healing',type:'spark',text:'Apologise for the specific thing. Not "I\'m sorry you felt that way." Name what you actually did.'},
{id:'h13',category:'healing',type:'advice',text:'When you notice yourself responding to your partner as if they are someone from your past, stop. Ask: who am I actually talking to right now? Return to the present person.',author:'Loving Better'},
{id:'h14',category:'healing',type:'quote',text:'A heart that has learned to guard itself can learn to open again. It just needs evidence that it is safe to do so.',author:'Loving Better'},
{id:'h15',category:'healing',type:'spark',text:'Seek help if you need it. A counsellor is not a sign of failure -- it is a sign of seriousness.'},
{id:'h16',category:'healing',type:'advice',text:'Grief has a place in healing a relationship -- grief for the time that was lost, for the pain that was caused. Let yourself grieve it. Then build from what is real.',author:'Loving Better'},
{id:'h17',category:'healing',type:'quote',text:'Forgiveness is not for them. It is for you. Releasing the debt sets you free, not them.',author:'Loving Better'},
{id:'h18',category:'healing',type:'spark',text:'What are you still waiting for an apology for? Can you begin to release it without one?'},
{id:'h19',category:'healing',type:'advice',text:'The season of healing inside a relationship requires both people to move simultaneously. One cannot wait for the other to go first. Both begin together, in faith, before the evidence is complete.',author:'Loving Better'},
{id:'h20',category:'healing',type:'quote',text:'Pain is not evidence that you are in the wrong relationship. It may be evidence that you are in the right one and doing the necessary work.',author:'Loving Better'},
{id:'h21',category:'healing',type:'spark',text:'The thing you most need to apologise for -- have you apologised for it specifically?'},
{id:'h22',category:'healing',type:'advice',text:'Do not perform healing. Healing is evidenced by changed behaviour, not stated intention. Watch what you actually do in the weeks and months that follow a commitment.',author:'Loving Better'},
{id:'h23',category:'healing',type:'quote',text:'The bravest thing two people can do is stay in a relationship after it has been difficult -- and choose to build something better than what broke.',author:'Loving Better'},
{id:'h24',category:'healing',type:'spark',text:'Progress is not returning to who you were before the hurt. It is becoming more whole because of what the hurt taught you.'},
{id:'h25',category:'healing',type:'advice',text:'Healing does not mean forgetting. It means the memory no longer controls you. You can hold what happened and still choose who you want to be because of it.',author:'Loving Better'},
{id:'h26',category:'healing',type:'quote',text:'Every relationship that has come through real difficulty carries something the easy ones do not: knowledge. You know each other now. That is not nothing.',author:'Loving Better'},
{id:'h27',category:'healing',type:'spark',text:'Tenderness is an act of healing. Be tender with them today -- and with yourself.'},
{id:'h28',category:'healing',type:'advice',text:'Some wounds need professional help. Asking for it is not weakness. It is the highest form of taking your relationship seriously.',author:'Loving Better'},
{id:'h29',category:'healing',type:'quote',text:'What broke between you is not proof that it cannot be rebuilt. Some of the strongest structures in the world have been repaired.',author:'Loving Better'},
{id:'h30',category:'healing',type:'spark',text:'Who are you without the hurt you are carrying? Start becoming that person.'},
{id:'h31',category:'healing',type:'advice',text:'The hardest person to forgive is sometimes yourself. For what you did. For what you allowed. For how long it took you. Give yourself the same grace you are extending to others.',author:'Loving Better'},
{id:'h32',category:'healing',type:'quote',text:'Healing together requires that both people are honest about what broke, not just what survived.',author:'Loving Better'},
{id:'h33',category:'healing',type:'spark',text:'Name what you are still carrying. Naming it is the first step toward setting it down.'},
{id:'h34',category:'healing',type:'advice',text:'When a wound reopens in a conversation -- when an old hurt comes flooding back -- name it in the moment: "This is touching something older for me. Can I tell you what?" That single act of self-awareness prevents most escalation.',author:'Loving Better'},
{id:'h35',category:'healing',type:'quote',text:'You are not defined by the worst thing that happened in this relationship. Neither are they.',author:'Loving Better'},
{id:'h36',category:'healing',type:'spark',text:'Let today be a day of softening, not hardening. Consciously.'},
{id:'h37',category:'healing',type:'advice',text:'If you find yourself having the same argument repeatedly, the issue is not the argument -- it is the unaddressed wound underneath it. Find the wound. Address that.',author:'Loving Better'},
{id:'h38',category:'healing',type:'quote',text:'Recovery in a relationship is not the absence of bad days. It is the presence of two people who face the bad days together.',author:'Loving Better'},
{id:'h39',category:'healing',type:'spark',text:'What would you need to believe about yourself to feel worthy of being fully loved? Begin to believe it.'},
{id:'h40',category:'healing',type:'advice',text:'Healing requires truth -- about what happened, what it cost, what it changed. Couples who skip the honest reckoning and jump to "we are fine" are not fine. They are a wound waiting to reopen.',author:'Loving Better'},
{id:'h41',category:'healing',type:'quote',text:'The courage it takes to stay and work through something is greater than the courage it takes to leave.',author:'Loving Better'},
{id:'h42',category:'healing',type:'spark',text:'Give them room to be different from who they were. People change. Let yours.'},
{id:'h43',category:'healing',type:'advice',text:'One of the most healing things you can say to your partner: "I see how this has affected you. I am sorry. I want to understand it more fully." Not a quick apology -- a genuine inquiry.',author:'Loving Better'},
{id:'h44',category:'healing',type:'quote',text:'Restoration is possible. Not as a return to what was, but as something genuinely new that could only be built from the ruins of what broke.',author:'Loving Better'},
{id:'h45',category:'healing',type:'spark',text:'What one thing could you release today -- fully, completely, without reservation?'},
{id:'h46',category:'healing',type:'advice',text:'Pay attention to the moments when the past is speaking louder than the present. Name them: "I think this is an old fear more than a current one." Then address both -- the current situation and the old source.',author:'Loving Better'},
{id:'h47',category:'healing',type:'quote',text:'Broken is not the same as finished. Some things have to break to become what they were always meant to be.',author:'Loving Better'},
{id:'h48',category:'healing',type:'spark',text:'Write yourself a letter of forgiveness today. For the ways you fell short. For the things you could not yet do. Then burn it or keep it -- but write it.'},
{id:'h49',category:'healing',type:'advice',text:'The goal of healing in a relationship is not to pretend the hurt did not happen. It is to create something between you that is bigger than the hurt. So that the hurt exists inside the love rather than the love existing inside the hurt.',author:'Loving Better'},
{id:'h50',category:'healing',type:'quote',text:'Two people who have hurt each other and chosen to repair it together know something about love that easy couples never will.',author:'Loving Better'},
// ── FAITH (40) ───────────────────────────────────────────────────────────────
{id:'f1',category:'faith',type:'scripture',text:'Love is patient, love is kind. It does not envy, it does not boast, it is not proud. It does not dishonour others, it is not self-seeking, it is not easily angered, it keeps no record of wrongs.',author:'1 Corinthians 13:4-5'},
{id:'f2',category:'faith',type:'advice',text:'Prayer is not a substitute for the hard work of communication and change. It is the context in which that work becomes possible. Bring the actual fears, the actual failures, before God.',author:'Loving Better'},
{id:'f3',category:'faith',type:'scripture',text:'Two are better than one, because they have a good return for their labour. If either of them falls down, one can help the other up.',author:'Ecclesiastes 4:9-10'},
{id:'f4',category:'faith',type:'advice',text:'The love described in scripture is not a description of what humans naturally do. It is a vision of what you are invited to become -- by grace, in relationship with God and with each other.',author:'Loving Better'},
{id:'f5',category:'faith',type:'scripture',text:'Be completely humble and gentle; be patient, bearing with one another in love. Make every effort to keep the unity of the Spirit through the bond of peace.',author:'Ephesians 4:2-3'},
{id:'f6',category:'faith',type:'quote',text:'To pray with someone is to let them hear you speak honestly to God. It is one of the most intimate forms of communication available to you.',author:'Loving Better'},
{id:'f7',category:'faith',type:'scripture',text:'In the multitude of counsellors there is safety.',author:'Proverbs 11:14'},
{id:'f8',category:'faith',type:'advice',text:'Do not use spiritual language to avoid difficult conversations. "God will fix it" is not a substitute for the specific work of addressing what is broken between you. God works through your willingness.',author:'Loving Better'},
{id:'f9',category:'faith',type:'scripture',text:'Bear with each other and forgive one another if any of you has a grievance against someone. Forgive as the Lord forgave you. And over all these virtues put on love, which binds them all together in perfect unity.',author:'Colossians 3:13-14'},
{id:'f10',category:'faith',type:'quote',text:'Faith in a relationship means believing in the person your partner is becoming, not only reacting to the person they are today.',author:'Loving Better'},
{id:'f11',category:'faith',type:'scripture',text:'Husbands, love your wives, just as Christ loved the church and gave himself up for her.',author:'Ephesians 5:25'},
{id:'f12',category:'faith',type:'spark',text:'Pray together tonight. Even one sentence each. It changes something.'},
{id:'f13',category:'faith',type:'scripture',text:'Above all, love each other deeply, because love covers over a multitude of sins.',author:'1 Peter 4:8'},
{id:'f14',category:'faith',type:'advice',text:'A couple that prays together is not just completing a spiritual discipline. They are making themselves vulnerable to each other in the presence of God. That shared vulnerability creates a bond that is hard to break.',author:'Loving Better'},
{id:'f15',category:'faith',type:'scripture',text:'Let your conversation be always full of grace, seasoned with salt, so that you may know how to answer everyone.',author:'Colossians 4:6'},
{id:'f16',category:'faith',type:'quote',text:'A relationship built on faith is not one that has no difficulties. It is one that takes its difficulties to the right place.',author:'Loving Better'},
{id:'f17',category:'faith',type:'scripture',text:'And now these three remain: faith, hope and love. But the greatest of these is love.',author:'1 Corinthians 13:13'},
{id:'f18',category:'faith',type:'spark',text:'What would it look like to bring God into this relationship as a daily presence, not just in crisis?'},
{id:'f19',category:'faith',type:'scripture',text:'A cord of three strands is not quickly broken.',author:'Ecclesiastes 4:12'},
{id:'f20',category:'faith',type:'advice',text:'Prayer together does not need to be long. Two people holding hands and each saying one honest sentence to God is enough to transform the atmosphere between them.',author:'Loving Better'},
{id:'f21',category:'faith',type:'scripture',text:'Love must be sincere. Hate what is evil; cling to what is good. Be devoted to one another in love. Honour one another above yourselves.',author:'Romans 12:9-10'},
{id:'f22',category:'faith',type:'quote',text:'The grace you give your partner is the grace you have received. You cannot give what you have not first accepted for yourself.',author:'Loving Better'},
{id:'f23',category:'faith',type:'scripture',text:'Be kind and compassionate to one another, forgiving each other, just as in Christ God forgave you.',author:'Ephesians 4:32'},
{id:'f24',category:'faith',type:'spark',text:'Write a prayer for your partner. Just for them. Not about the relationship -- for them, their peace, their calling.'},
{id:'f25',category:'faith',type:'scripture',text:'Therefore what God has joined together, let no one separate.',author:'Mark 10:9'},
{id:'f26',category:'faith',type:'advice',text:'Some seasons of a relationship will require faith more than feeling. The feeling will return. In the season when it is quiet, faith that God\'s plan for you is good is what keeps you building.',author:'Loving Better'},
{id:'f27',category:'faith',type:'scripture',text:'Let us not become weary in doing good, for at the proper time we will reap a harvest if we do not give up.',author:'Galatians 6:9'},
{id:'f28',category:'faith',type:'quote',text:'God sees not only where you are in this relationship -- He sees where you are going. Trust the process He is using to get you there.',author:'Loving Better'},
{id:'f29',category:'faith',type:'scripture',text:'For I know the plans I have for you, declares the Lord, plans to prosper you and not to harm you, plans to give you hope and a future.',author:'Jeremiah 29:11'},
{id:'f30',category:'faith',type:'spark',text:'Is your faith influencing how you treat each other daily, or only when things get desperate?'},
{id:'f31',category:'faith',type:'scripture',text:'Do nothing out of selfish ambition or vain conceit. Rather, in humility value others above yourselves.',author:'Philippians 2:3'},
{id:'f32',category:'faith',type:'advice',text:'Spiritual leadership in a relationship is not about control. It is about setting the tone for how both people treat each other, approach God, and navigate difficulty. It is servant leadership first.',author:'Loving Better'},
{id:'f33',category:'faith',type:'scripture',text:'My command is this: Love each other as I have loved you.',author:'John 15:12'},
{id:'f34',category:'faith',type:'spark',text:'Read one verse together this week. Just one. Talk about what it means for your relationship.'},
{id:'f35',category:'faith',type:'scripture',text:'Trust in the Lord with all your heart and lean not on your own understanding; in all your ways submit to him, and he will make your paths straight.',author:'Proverbs 3:5-6'},
{id:'f36',category:'faith',type:'advice',text:'When the relationship is hard, remember: the enemy of a godly relationship is not the conflict between you -- it is the enemy outside the relationship who benefits from the division. Fight together, not against each other.',author:'Loving Better'},
{id:'f37',category:'faith',type:'scripture',text:'Love never fails.',author:'1 Corinthians 13:8'},
{id:'f38',category:'faith',type:'spark',text:'What is one thing you believe God wants to build in your relationship that you have not yet given Him permission to build?'},
{id:'f39',category:'faith',type:'scripture',text:'Do not be anxious about anything, but in every situation, by prayer and petition, with thanksgiving, present your requests to God.',author:'Philippians 4:6'},
{id:'f40',category:'faith',type:'advice',text:'Faith and action are not opposites in a relationship. Faith says: I believe this is possible. Action says: I am doing the work that makes it so. Both are required. Neither replaces the other.',author:'Loving Better'},
// ── FOR HIM (60) ─────────────────────────────────────────────────────────────
{id:'him1',category:'him',type:'affirmation',text:'You have more to offer than what you provide. She knows this. She is waiting for you to offer the rest -- the presence, the words, the willingness to be known fully.',author:'Loving Better'},
{id:'him2',category:'him',type:'advice',text:'Staying quiet to keep the peace is not peace. It is a debt deferred. Every time you absorb rather than address, you add to an account that will eventually demand payment.',author:'Loving Better'},
{id:'him3',category:'him',type:'spark',text:'The words she needs most are specific: what you noticed, what you felt, what you are grateful for.'},
{id:'him4',category:'him',type:'advice',text:'The fear of difficult conversations is real. But the fear costs more than the conversation. Every avoided talk teaches her that she is not safe enough here for honesty.',author:'Loving Better'},
{id:'him5',category:'him',type:'affirmation',text:'You are not required to have the perfect words. You are required to try. She does not need eloquence. She needs to know that she is worth the effort.',author:'Loving Better'},
{id:'him6',category:'him',type:'spark',text:'Tell her one specific thing you love about her today. Not general -- something you actually noticed.'},
{id:'him7',category:'him',type:'advice',text:'Physical intimacy and emotional intimacy are connected but not the same. When you seek closeness without consistently offering emotional presence, she experiences the imbalance even when she cannot name it.',author:'Loving Better'},
{id:'him8',category:'him',type:'affirmation',text:'You are not the worst version of yourself that has appeared in this relationship. You are the version reading this, trying, not leaving. That version can also be the one that changes.',author:'Loving Better'},
{id:'him9',category:'him',type:'spark',text:'Initiate something today. A check-in, a hug, a conversation. Do not wait for her to come to you.'},
{id:'him10',category:'him',type:'advice',text:'When she goes quiet and something seems heavy in her, that is not the moment to look away. That is the moment to come toward her. You do not need to fix it. Just be present to it.',author:'Loving Better'},
{id:'him11',category:'him',type:'affirmation',text:'Provision is good and it is valued. But she does not need you to earn more. She needs you to show up more fully to the life you already share.',author:'Loving Better'},
{id:'him12',category:'him',type:'spark',text:'Ask her what she needs from you this week -- specifically. Then do it.'},
{id:'him13',category:'him',type:'advice',text:'A man who learns to express what he feels, who stays in the hard conversation rather than retreating, who leads with presence -- that man will be more fully alive. More capable of the connection you both want.',author:'Loving Better'},
{id:'him14',category:'him',type:'affirmation',text:'The specific thing she is asking for -- to know you, to have access to the actual person -- is not an unreasonable ask. It is the most reasonable ask a person in love can make.',author:'Loving Better'},
{id:'him15',category:'him',type:'spark',text:'Write down one commitment you will make this week. Specific. Keep it.'},
{id:'him16',category:'him',type:'advice',text:'Make the apology specific. "I am sorry I was distant" is not enough. "I am sorry that when you needed me last Tuesday I turned away instead of coming toward you" -- that one lands.',author:'Loving Better'},
{id:'him17',category:'him',type:'affirmation',text:'The silent man who absorbs everything alone is not strong. He is isolated. Strength in a relationship looks like letting the person you love actually know you.',author:'Loving Better'},
{id:'him18',category:'him',type:'spark',text:'What is she carrying right now that you could help carry? Ask her.'},
{id:'him19',category:'him',type:'advice',text:'Show up for the small things. The bad day. The moment when she is overwhelmed and needs five minutes of full presence. These moments are not interruptions. They are the relationship.',author:'Loving Better'},
{id:'him20',category:'him',type:'affirmation',text:'You chose her. Keep choosing her -- in the specific, daily, unglamorous ways that actually mean something.',author:'Loving Better'},
{id:'him21',category:'him',type:'spark',text:'Hold her today -- not because anything is happening, just because you want to be near her.'},
{id:'him22',category:'him',type:'advice',text:'The compliment you thought but did not say -- say it. The appreciation you felt but held back -- give it. The love you carried inside but did not express -- express it. Stop keeping it to yourself.',author:'Loving Better'},
{id:'him23',category:'him',type:'affirmation',text:'She is not asking you to change who you are. She is asking you to let who you are be fully visible to her. There is a difference.',author:'Loving Better'},
{id:'him24',category:'him',type:'spark',text:'What would she say she needs more of from you? Ask her. Then provide it.'},
{id:'him25',category:'him',type:'advice',text:'Your emotional availability is not separate from your spiritual calling. A man who cannot be emotionally present to his partner will struggle to be fully present to anything God has called him to build.',author:'Loving Better'},
{id:'him26',category:'him',type:'affirmation',text:'You are being shaped. The difficulty of this relationship is not punishment -- it is formation. The man on the other side of this work is someone worth becoming.',author:'Loving Better'},
{id:'him27',category:'him',type:'spark',text:'Pray for her specifically tonight. Not for the relationship. For her -- her peace, her calling, her joy.'},
{id:'him28',category:'him',type:'advice',text:'You cannot lead someone you are hiding from. Leadership in a relationship requires that she knows you -- your fears, your goals, your failures, your faith. You cannot lead from behind a wall.',author:'Loving Better'},
{id:'him29',category:'him',type:'affirmation',text:'One kept promise this week changes something. Do not underestimate the power of a small thing done exactly as you said you would.',author:'Loving Better'},
{id:'him30',category:'him',type:'spark',text:'Notice her today. Really notice her. Then tell her what you saw.'},
{id:'him31',category:'him',type:'advice',text:'When she raises something hard, resist the first impulse to defend. Replace the defense with a question: "Help me understand what that felt like for you." The question is worth more than any explanation.',author:'Loving Better'},
{id:'him32',category:'him',type:'affirmation',text:'The man she needs is not a different man. He is the fullest version of the man you already are. Become that version.',author:'Loving Better'},
{id:'him33',category:'him',type:'spark',text:'What would it look like to be fully emotionally present to her for one complete hour today?'},
{id:'him34',category:'him',type:'advice',text:'Every time you choose the conversation over the silence, you are telling her something important: that she is worth more to you than your comfort. She will remember those moments.',author:'Loving Better'},
{id:'him35',category:'him',type:'affirmation',text:'The love you feel for her is real. The task now is to make it visible. Not occasionally -- consistently.',author:'Loving Better'},
{id:'him36',category:'him',type:'spark',text:'What does she need to hear from you today that she has never heard you say?'},
{id:'him37',category:'him',type:'advice',text:'Check in with her at the end of each day -- not about tasks, about her. One question, genuinely asked, fully listened to. Do this every day for thirty days and watch what changes between you.',author:'Loving Better'},
{id:'him38',category:'him',type:'affirmation',text:'Your silence costs her more than you know. Your voice -- honest, present, trying -- costs you more than you fear. The second cost is worth it.',author:'Loving Better'},
{id:'him39',category:'him',type:'spark',text:'Be the kind of man she would be proud to describe to her daughter.'},
{id:'him40',category:'him',type:'advice',text:'When she is in pain -- any kind of pain -- the first and only job is to be present to it. Not to explain it, not to fix it, not to point out that you warned her. Present. There. Holding her reality.',author:'Loving Better'},
{id:'him41',category:'him',type:'affirmation',text:'Every version of you that chooses honesty over avoidance, presence over withdrawal, love over comfort -- that version is who you were built to be.',author:'Loving Better'},
{id:'him42',category:'him',type:'spark',text:'What is the most loving thing you could do for her in the next ten minutes? Do that.'},
{id:'him43',category:'him',type:'advice',text:'Do not wait until you feel ready to communicate. Readiness in communication is often just the absence of vulnerability disguised as the absence of opportunity. The opportunity is now.',author:'Loving Better'},
{id:'him44',category:'him',type:'affirmation',text:'She stayed. Even when she had reasons to leave. Honour that by becoming someone who makes staying feel like the obvious right choice.',author:'Loving Better'},
{id:'him45',category:'him',type:'spark',text:'What does she celebrate about you? Do you know? Ask her.'},
{id:'him46',category:'him',type:'advice',text:'Physical presence and emotional presence are not the same. Be emotionally present today -- attentive to her mood, responsive to her words, attuned to what is beneath the surface.',author:'Loving Better'},
{id:'him47',category:'him',type:'affirmation',text:'You do not have to have it all together to be loved. You have to be honest about where you are. That honesty is itself a form of love.',author:'Loving Better'},
{id:'him48',category:'him',type:'spark',text:'Put her name in your prayer today. Specifically. By name. Let God hear how much she matters to you.'},
{id:'him49',category:'him',type:'advice',text:'The pressure you are carrying outside the relationship -- the work, the expectations, the financial stress -- is real. But she cannot help carry it if you do not let her see it. Let her in. She is on your side.',author:'Loving Better'},
{id:'him50',category:'him',type:'affirmation',text:'You are enough to be the man this relationship needs. Not because you are perfect but because you are willing. Willingness is the only raw material you need to begin.',author:'Loving Better'},
{id:'him51',category:'him',type:'spark',text:'What is one thing she does that you have never properly thanked her for? Thank her for it today.'},
{id:'him52',category:'him',type:'advice',text:'If she feels like she is doing the emotional labour of the relationship alone, she is not wrong. Share the load. Initiate. Ask the questions. Bring things up. That is what partnership looks like.',author:'Loving Better'},
{id:'him53',category:'him',type:'affirmation',text:'The version of you that shows up fully for her is the version that will be most effective in every other area of your life. These things are connected.',author:'Loving Better'},
{id:'him54',category:'him',type:'spark',text:'Learn one new thing about her this week. Something you do not already know. Stay curious.'},
{id:'him55',category:'him',type:'advice',text:'Do not make her guess how you feel. She should not have to decode your behaviour or interpret your silences or ask three times before you say what is happening with you. Say it first.',author:'Loving Better'},
{id:'him56',category:'him',type:'affirmation',text:'Every day you choose to be better than you were yesterday is a day you are building something worthy of what she is offering you.',author:'Loving Better'},
{id:'him57',category:'him',type:'spark',text:'What would she say is the best thing about being loved by you? Is that what you want her to say?'},
{id:'him58',category:'him',type:'advice',text:'Create rituals with her. Small, repeated, intentional moments that belong only to the two of you. These rituals become the connective tissue of the relationship.',author:'Loving Better'},
{id:'him59',category:'him',type:'affirmation',text:'You are not behind. You are becoming. There is a difference. The work you are doing now matters. Do not stop.',author:'Loving Better'},
{id:'him60',category:'him',type:'spark',text:'Lead today. Not by telling -- by going first. In vulnerability. In apology. In kindness. Go first.'},
// ── FOR HER (60) ─────────────────────────────────────────────────────────────
{id:'her1',category:'her',type:'affirmation',text:'His limitations as a communicator are not evidence of your worth. They are evidence of his development as a partner. The gap is in him. You are not the proof of the gap.',author:'Loving Better'},
{id:'her2',category:'her',type:'advice',text:'Your history with your family taught you real things. But it is worth asking: am I responding to what is happening right now, or to what I was trained to fear? Both can be present. They deserve separate responses.',author:'Loving Better'},
{id:'her3',category:'her',type:'spark',text:'You are not too much. You are the right amount. And you deserve someone who rises to meet you.'},
{id:'her4',category:'her',type:'advice',text:'Remaining open to the possibility that he can change is a risk. But closing to it guarantees a future that staying open might prevent. Discernment and openness are not opposites.',author:'Loving Better'},
{id:'her5',category:'her',type:'affirmation',text:'You are perceptive, honest, capable of extraordinary loyalty. Do not let any season diminish your understanding of your own value.',author:'Loving Better'},
{id:'her6',category:'her',type:'spark',text:'Receive something he does today without minimising it or measuring it against what is missing.'},
{id:'her7',category:'her',type:'advice',text:'There is a version of independence that protects you from pain by ensuring you never fully need anyone. That version keeps you safe. It also keeps you alone inside your own relationship.',author:'Loving Better'},
{id:'her8',category:'her',type:'affirmation',text:'The softness you have been guarding is still there. It is waiting for a safe place to emerge. You are allowed to create that place with someone who is genuinely trying to be worthy of it.',author:'Loving Better'},
{id:'her9',category:'her',type:'spark',text:'Name one thing you appreciate about him today -- to him, out loud, directly.'},
{id:'her10',category:'her',type:'advice',text:'There is a difference between the articulation that comes from the wound and the articulation that comes from the war. The wound invites the other person in. The war closes them down. Check which one you are speaking from.',author:'Loving Better'},
{id:'her11',category:'her',type:'affirmation',text:'Your parents\' marriage is a warning, not a verdict. You are writing a different story. But the author of that story must be you -- actively, deliberately, through specific daily choices.',author:'Loving Better'},
{id:'her12',category:'her',type:'spark',text:'What would it feel like to receive what he offers today without pre-rejecting it?'},
{id:'her13',category:'her',type:'advice',text:'Healing your own wounds is not a prerequisite for being loved. But it will make loving and being loved significantly easier. Do it for yourself first.',author:'Loving Better'},
{id:'her14',category:'her',type:'affirmation',text:'You are not asking too much when you ask to be fully known and consistently loved. That is what love is for. Do not shrink the ask.',author:'Loving Better'},
{id:'her15',category:'her',type:'spark',text:'What would the most generous version of yourself do with what he gave you today? Do that.'},
{id:'her16',category:'her',type:'advice',text:'Your directness is a gift, not a flaw. But how you use it determines whether it builds or destroys. The same clarity that makes you extraordinary can be wielded as a weapon or offered as a gift.',author:'Loving Better'},
{id:'her17',category:'her',type:'affirmation',text:'A woman who can see her own future clearly -- who refuses to believe she will fail -- is someone worth building a life beside.',author:'Loving Better'},
{id:'her18',category:'her',type:'spark',text:'Give him room today to try. Do not score the attempt before it is finished.'},
{id:'her19',category:'her',type:'advice',text:'When you decide in advance how someone will behave, you stop giving them room to surprise you. Stay curious. Let him surprise you.',author:'Loving Better'},
{id:'her20',category:'her',type:'affirmation',text:'You stayed. Through everything. That is not weakness -- that is the rarest and most valuable form of strength.',author:'Loving Better'},
{id:'her21',category:'her',type:'spark',text:'The version of you that is fully loved and fully known is waiting on the other side of being fully open. She deserves to exist.'},
{id:'her22',category:'her',type:'advice',text:'Your need for emotional presence, for words of affirmation, for being held when you are in pain -- these are not high maintenance. They are completely human. Name them without apology.',author:'Loving Better'},
{id:'her23',category:'her',type:'affirmation',text:'You are worth his effort. The times he did not give it do not change that. His failure to see your worth is not evidence of your worth -- it is evidence of his limited vision at that time.',author:'Loving Better'},
{id:'her24',category:'her',type:'spark',text:'What do you need today? State it clearly. Let yourself be cared for.'},
{id:'her25',category:'her',type:'advice',text:'You do not have to choose between being loved fully and being loved by him specifically. But you do have to give him genuine room to grow -- not a performance of room, but real room, with real patience.',author:'Loving Better'},
{id:'her26',category:'her',type:'affirmation',text:'Your discernment is a gift. Trust it without letting it sentence someone before the evidence is complete.',author:'Loving Better'},
{id:'her27',category:'her',type:'spark',text:'Take care of yourself today. You cannot pour from empty. Fill yourself first.'},
{id:'her28',category:'her',type:'advice',text:'The things you love about him -- the things that made you choose him -- are still there. In the difficult season, actively look for them. What you focus on grows.',author:'Loving Better'},
{id:'her29',category:'her',type:'affirmation',text:'Your capacity to love is enormous. Do not let the pain of an imperfect season convince you that the capacity itself is a liability.',author:'Loving Better'},
{id:'her30',category:'her',type:'spark',text:'Write yourself a note today about the woman you are becoming. She is worth knowing.'},
{id:'her31',category:'her',type:'advice',text:'When you are in the war, you cannot see the wound. Step back from the battle. Find the wound. Speak from there instead of from the heat of the fight.',author:'Loving Better'},
{id:'her32',category:'her',type:'affirmation',text:'Your feelings are data, not verdicts. They tell you something important about your experience. They do not always tell you the complete truth about the situation.',author:'Loving Better'},
{id:'her33',category:'her',type:'spark',text:'What is one fear you have about this relationship that you have not said out loud? Name it -- to yourself first, then to him.'},
{id:'her34',category:'her',type:'advice',text:'The version of you that withholds to protect yourself is the same version that ensures you never feel fully loved. Opening is the risk. It is also the only path to what you actually want.',author:'Loving Better'},
{id:'her35',category:'her',type:'affirmation',text:'You have been honest in this relationship at great personal cost. That honesty is one of the most valuable things you have brought to it.',author:'Loving Better'},
{id:'her36',category:'her',type:'spark',text:'What would you tell your younger self about love, if you could? Are you living by that advice?'},
{id:'her37',category:'her',type:'advice',text:'You are allowed to need things. You are allowed to ask for them. You are allowed to feel hurt when they are not given. And you are also allowed to believe that they can be given -- if you create enough space for the giving.',author:'Loving Better'},
{id:'her38',category:'her',type:'affirmation',text:'Every woman who insists on being fully loved is doing something radical. Hold that line. Just make sure the standard is for love, not perfection.',author:'Loving Better'},
{id:'her39',category:'her',type:'spark',text:'One thing you know about love now that you did not know when you entered this relationship: what is it?'},
{id:'her40',category:'her',type:'advice',text:'Your pain at the things that went wrong is valid. And so is his pain at the things that went wrong for him. Both can be true at the same time. This is not a competition.',author:'Loving Better'},
{id:'her41',category:'her',type:'affirmation',text:'You are not broken. You are bending under a weight you were never meant to carry alone. Put some of it down.',author:'Loving Better'},
{id:'her42',category:'her',type:'spark',text:'Let him see one thing today that you usually keep hidden. The vulnerability will do more than a hundred right words.'},
{id:'her43',category:'her',type:'advice',text:'The love you are looking for -- the kind that is steady, that notices you, that stays -- is possible. The question is whether you can stay open long enough to let it develop.',author:'Loving Better'},
{id:'her44',category:'her',type:'affirmation',text:'You are someone worth loving consistently and specifically. Do not accept anything less as normal. But also do not confuse growth in progress with the finished product.',author:'Loving Better'},
{id:'her45',category:'her',type:'spark',text:'What is the most loving thing you could give him today that would cost you something?'},
{id:'her46',category:'her',type:'advice',text:'The woman who can both name her needs and create space for her partner to meet them -- that is the most powerful position in a relationship. Not the one who withholds, and not the one who only receives.',author:'Loving Better'},
{id:'her47',category:'her',type:'affirmation',text:'Your insistence on real love is not a burden. It is a gift to any man willing to rise to it.',author:'Loving Better'},
{id:'her48',category:'her',type:'spark',text:'What would it look like to trust this process a little more than you did yesterday?'},
{id:'her49',category:'her',type:'advice',text:'One of the most powerful things you can say: "I am working on my own patterns too. I am not just waiting for you to change -- I am also in the process." That kind of mutual accountability is the fastest path forward.',author:'Loving Better'},
{id:'her50',category:'her',type:'affirmation',text:'The woman who does the work on herself, who names her wounds without letting them define her, who loves with her eyes open -- that woman is extraordinary. Keep becoming her.',author:'Loving Better'},
{id:'her51',category:'her',type:'spark',text:'Tell him one thing he has done recently that you appreciated and have not said yet.'},
{id:'her52',category:'her',type:'advice',text:'You have every right to have standards. You also have every right to choose whether to give someone time to meet them. Make that choice consciously, not reactively.',author:'Loving Better'},
{id:'her53',category:'her',type:'affirmation',text:'The love you are building is not a consolation prize. It is a genuine, specific, hard-won thing. Treat it that way.',author:'Loving Better'},
{id:'her54',category:'her',type:'spark',text:'What is something about yourself that you have been ashamed of in this relationship? Can you let yourself be known in that area?'},
{id:'her55',category:'her',type:'advice',text:'When you are tempted to use everything he has ever done wrong as evidence against him, stop. Ask: am I building a case, or am I trying to build a relationship? You cannot do both at the same time.',author:'Loving Better'},
{id:'her56',category:'her',type:'affirmation',text:'You deserve to be with someone who chooses you -- not out of obligation, not out of fear of starting over, but because you are the person they most want to build something with.',author:'Loving Better'},
{id:'her57',category:'her',type:'spark',text:'What does your joy look like? Does he know? Have you shown him?'},
{id:'her58',category:'her',type:'advice',text:'Let yourself be delighted by him sometimes. Not just evaluated. Delighted. The relationship needs room for delight as much as it needs room for honesty.',author:'Loving Better'},
{id:'her59',category:'her',type:'affirmation',text:'Every version of you that chooses to stay and build rather than retreat and protect is writing a story that your future self will be grateful for.',author:'Loving Better'},
{id:'her60',category:'her',type:'spark',text:'What is the best version of this relationship? Describe it. Then ask: what would I need to bring to make that possible?'},
// ── DAILY SPARKS (120) ───────────────────────────────────────────────────────
{id:'d1',category:'daily',type:'spark',text:'What is one thing you have been meaning to say? Say it today.'},
{id:'d2',category:'daily',type:'spark',text:'Look at them today like it is the first time you have really seen them in a while.'},
{id:'d3',category:'daily',type:'spark',text:'Make the repair. Whatever was left rough from the last few days -- smooth it today.'},
{id:'d4',category:'daily',type:'spark',text:'What is one thing they did recently that you have not thanked them for? Do that now.'},
{id:'d5',category:'daily',type:'spark',text:'Touch them today -- not from desire, from warmth.'},
{id:'d6',category:'daily',type:'spark',text:'Put the phone down for one hour tonight and be fully with them.'},
{id:'d7',category:'daily',type:'spark',text:'Say: "I was thinking about you." Mean it.'},
{id:'d8',category:'daily',type:'spark',text:'What is one thing you could do today that would make them feel less alone?'},
{id:'d9',category:'daily',type:'spark',text:'Remember why you chose them. Not the worst version. The version that made you choose.'},
{id:'d10',category:'daily',type:'spark',text:'Before the day ends: say something kind, something true, something you mean.'},
{id:'d11',category:'daily',type:'spark',text:'Every day you choose them again is a vote for the future you both want.'},
{id:'d12',category:'daily',type:'spark',text:'Ask about one thing they care about that has nothing to do with you or the relationship.'},
{id:'d13',category:'daily',type:'spark',text:'The morning sets the tone. Make the first moment between you a warm one today.'},
{id:'d14',category:'daily',type:'spark',text:'Laughter is oxygen for a relationship. Find something to laugh about together today.'},
{id:'d15',category:'daily',type:'spark',text:'One genuine, specific compliment. Something you actually noticed.'},
{id:'d16',category:'daily',type:'spark',text:'Pray for them today. Not about the relationship -- just for them.'},
{id:'d17',category:'daily',type:'spark',text:'What would your relationship look like if you both acted at your best today? Do that.'},
{id:'d18',category:'daily',type:'spark',text:'Say "I love you" slowly today. Make it land.'},
{id:'d19',category:'daily',type:'spark',text:'Catch yourself before you respond in a way you will regret. Take the breath. Choose differently.'},
{id:'d20',category:'daily',type:'spark',text:'Check in with yourself: what am I bringing to this relationship today?'},
{id:'d21',category:'daily',type:'spark',text:'Do one thing for them today that they did not ask for and would not expect.'},
{id:'d22',category:'daily',type:'spark',text:'Notice what they are feeling before they say it. Then name it gently.'},
{id:'d23',category:'daily',type:'spark',text:'Start the conversation you have been delaying. The right moment is not coming. This is it.'},
{id:'d24',category:'daily',type:'spark',text:'What would make their day easier today? Do that thing.'},
{id:'d25',category:'daily',type:'spark',text:'Celebrate something small together today. Small victories need witnesses.'},
{id:'d26',category:'daily',type:'spark',text:'Put their need ahead of your comfort in one small moment today.'},
{id:'d27',category:'daily',type:'spark',text:'Tell them what you see when you look at them. Not what you wish they were. What they actually are.'},
{id:'d28',category:'daily',type:'spark',text:'Ask: "What made you smile today?" Then listen to the whole answer.'},
{id:'d29',category:'daily',type:'spark',text:'Make eye contact when they are talking. Not phone contact. Eye contact.'},
{id:'d30',category:'daily',type:'spark',text:'What is one thing from last week that went unacknowledged? Acknowledge it today.'},
{id:'d31',category:'daily',type:'spark',text:'Be interested, not just interesting. Ask more than you tell today.'},
{id:'d32',category:'daily',type:'spark',text:'Protect your energy today. You cannot love well when you are completely depleted.'},
{id:'d33',category:'daily',type:'spark',text:'Let something go today. One grievance, held past its usefulness, released.'},
{id:'d34',category:'daily',type:'spark',text:'"I\'m proud of you" -- when was the last time you said that? Say it today.'},
{id:'d35',category:'daily',type:'spark',text:'Cook with them or for them. Food made with intention is love made edible.'},
{id:'d36',category:'daily',type:'spark',text:'Write them one sentence today -- by hand or by message -- that says what is true.'},
{id:'d37',category:'daily',type:'spark',text:'Be patient today in one moment where patience does not come easily to you.'},
{id:'d38',category:'daily',type:'spark',text:'What have they been carrying lately that you have not asked about? Ask today.'},
{id:'d39',category:'daily',type:'spark',text:'Sit in silence together today without filling it. Comfortable silence is intimacy.'},
{id:'d40',category:'daily',type:'spark',text:'Give them your full attention for one uninterrupted hour today.'},
{id:'d41',category:'daily',type:'spark',text:'Apologise for the small thing you glossed over yesterday. Small apologies prevent large resentments.'},
{id:'d42',category:'daily',type:'spark',text:'Tell them they are enough. Mean it. Because they are.'},
{id:'d43',category:'daily',type:'spark',text:'Ask them what they dream about. Not goals -- actual dreams.'},
{id:'d44',category:'daily',type:'spark',text:'Be someone they are glad to come home to today.'},
{id:'d45',category:'daily',type:'spark',text:'What is the one thing you can do today that shows you have been paying attention?'},
{id:'d46',category:'daily',type:'spark',text:'Show up for the ordinary moment today as if it were extraordinary. Because it is.'},
{id:'d47',category:'daily',type:'spark',text:'What story are you telling yourself about the relationship today? Is it the most generous one?'},
{id:'d48',category:'daily',type:'spark',text:'Before you speak, ask: is this kind, is this true, is this necessary?'},
{id:'d49',category:'daily',type:'spark',text:'Name one thing that is going well. Out loud. Today.'},
{id:'d50',category:'daily',type:'spark',text:'Thank them for something they do consistently that you take for granted.'},
{id:'d51',category:'daily',type:'spark',text:'Let them be right today. Even if they are not completely right. Let it go.'},
{id:'d52',category:'daily',type:'spark',text:'Ask: "What do you need from me today?" Then provide exactly that.'},
{id:'d53',category:'daily',type:'spark',text:'The version of this relationship you most want -- what would you do differently today to move toward it?'},
{id:'d54',category:'daily',type:'spark',text:'One act of service today, done without being asked and without mentioning it.'},
{id:'d55',category:'daily',type:'spark',text:'Look for what is growing, not just what is broken.'},
{id:'d56',category:'daily',type:'spark',text:'Hold space for their feelings today without trying to fix them.'},
{id:'d57',category:'daily',type:'spark',text:'Whatever you most need them to give you -- give it to them first today.'},
{id:'d58',category:'daily',type:'spark',text:'Celebrate them today. Not for what they do. For who they are.'},
{id:'d59',category:'daily',type:'spark',text:'Tomorrow you will wish you had started today. Start today.'},
{id:'d60',category:'daily',type:'spark',text:'Be curious about them today. They are more than you currently know.'},
{id:'d61',category:'daily',type:'spark',text:'Greet them when they walk in like you are genuinely happy to see them.'},
{id:'d62',category:'daily',type:'spark',text:'Choose the generous interpretation today. Of their action, their silence, their mood.'},
{id:'d63',category:'daily',type:'spark',text:'Say thank you for one thing they do that you rarely acknowledge.'},
{id:'d64',category:'daily',type:'spark',text:'What does love look like in the next hour? Do that.'},
{id:'d65',category:'daily',type:'spark',text:'Do not let this day end without making some real contact with their soul, not just their presence.'},
{id:'d66',category:'daily',type:'spark',text:'One moment of full presence today. No distractions. Just them.'},
{id:'d67',category:'daily',type:'spark',text:'Check: are you being the partner you want to have? If not, what one thing can you adjust?'},
{id:'d68',category:'daily',type:'spark',text:'Decide to have a good day in this relationship today. Decisions create conditions.'},
{id:'d69',category:'daily',type:'spark',text:'What is one thing that made you fall for them that you have not thought about recently?'},
{id:'d70',category:'daily',type:'spark',text:'Bring them something small today -- a drink, a snack, something they like. No reason needed.'},
{id:'d71',category:'daily',type:'spark',text:'Speak gently today. Not because the hard things are not true -- because gentleness is what makes them land.'},
{id:'d72',category:'daily',type:'spark',text:'What do they worry about that you have never fully acknowledged? Acknowledge it today.'},
{id:'d73',category:'daily',type:'spark',text:'Choose them in a moment when it is inconvenient to do so. That is where real love lives.'},
{id:'d74',category:'daily',type:'spark',text:'Share something from your own inner world today that you would normally keep private.'},
{id:'d75',category:'daily',type:'spark',text:'What is something they are good at that you rarely name out loud? Name it today.'},
{id:'d76',category:'daily',type:'spark',text:'Let the conversation go longer than you planned. See where it takes you.'},
{id:'d77',category:'daily',type:'spark',text:'Do not check your phone for the first 20 minutes you are together today.'},
{id:'d78',category:'daily',type:'spark',text:'Ask: "What is something you\'ve been wanting to talk about but haven\'t?" Then listen.'},
{id:'d79',category:'daily',type:'spark',text:'What would you do today if you fully believed this relationship was going to work?'},
{id:'d80',category:'daily',type:'spark',text:'Plan something small to look forward to together. Hope has a future dimension.'},
{id:'d81',category:'daily',type:'spark',text:'The way you respond to them in the small moments is the relationship. Make those moments count.'},
{id:'d82',category:'daily',type:'spark',text:'What does joy look like in this relationship? Create one moment of it today.'},
{id:'d83',category:'daily',type:'spark',text:'One honest word today is worth more than a hundred comfortable ones.'},
{id:'d84',category:'daily',type:'spark',text:'When they walk in the room, stop what you are doing. Even for thirty seconds. Just be with them.'},
{id:'d85',category:'daily',type:'spark',text:'What is one thing they said last week that you want to come back to? Come back to it today.'},
{id:'d86',category:'daily',type:'spark',text:'Be interested in their day -- not as information gathering, as genuine curiosity about someone you love.'},
{id:'d87',category:'daily',type:'spark',text:'What would it look like to lead with warmth today, even before you know what kind of day it will be?'},
{id:'d88',category:'daily',type:'spark',text:'Find one thing to admire about them today and tell them what it is.'},
{id:'d89',category:'daily',type:'spark',text:'Do not save the good conversation for the weekend. Have it today.'},
{id:'d90',category:'daily',type:'spark',text:'What is the most loving thing you could say to them right now? Say it.'},
{id:'d91',category:'daily',type:'spark',text:'Notice when they are trying -- even imperfectly -- and acknowledge the try.'},
{id:'d92',category:'daily',type:'spark',text:'Create a small moment of beauty in their day. You know them well enough to know what that looks like.'},
{id:'d93',category:'daily',type:'spark',text:'The effort you put in today is the foundation of tomorrow. Put in real effort today.'},
{id:'d94',category:'daily',type:'spark',text:'What is one thing you need to say that you keep almost saying? Almost does not count. Say it.'},
{id:'d95',category:'daily',type:'spark',text:'Resist the urge to be right today. Choose connection over correctness.'},
{id:'d96',category:'daily',type:'spark',text:'Give them at least one full minute of uninterrupted, undivided, genuine attention today.'},
{id:'d97',category:'daily',type:'spark',text:'The small kindness done consistently is what love looks like from the inside.'},
{id:'d98',category:'daily',type:'spark',text:'What are you grateful for about them today, specifically? Let them hear it.'},
{id:'d99',category:'daily',type:'spark',text:'Be the kind of person they can come to when things go wrong. Make sure they know that.'},
{id:'d100',category:'daily',type:'spark',text:'End today with more warmth between you than you started with. That is the whole job.'},
{id:'d101',category:'daily',type:'spark',text:'One question today that you genuinely do not know the answer to. Ask it.'},
{id:'d102',category:'daily',type:'spark',text:'What is the kindest thing you could say about them to someone else? Say it to them instead.'},
{id:'d103',category:'daily',type:'spark',text:'Make a small promise today. Keep it before the day is over.'},
{id:'d104',category:'daily',type:'spark',text:'Today: less phone, more them.'},
{id:'d105',category:'daily',type:'spark',text:'What have you been taking for granted? Stop taking it for granted. Today.'},
{id:'d106',category:'daily',type:'spark',text:'Be someone they feel seen by today. See them first.'},
{id:'d107',category:'daily',type:'spark',text:'What would you do differently today if you knew this was the most important day of the relationship?'},
{id:'d108',category:'daily',type:'spark',text:'Reach for their hand today. Just because.'},
{id:'d109',category:'daily',type:'spark',text:'Say the hard thing gently. The gentleness is not dishonesty -- it is skill.'},
{id:'d110',category:'daily',type:'spark',text:'What is one word that describes how you want them to feel after being with you today? Live that word.'},
{id:'d111',category:'daily',type:'spark',text:'Sit with them in whatever they are feeling today, without trying to change it.'},
{id:'d112',category:'daily',type:'spark',text:'Choose gratitude for them specifically today. Not in general -- for three specific things.'},
{id:'d113',category:'daily',type:'spark',text:'What would today look like if you were giving 100% to this relationship? Give that.'},
{id:'d114',category:'daily',type:'spark',text:'A hug that lasts long enough to actually feel them. Give that today.'},
{id:'d115',category:'daily',type:'spark',text:'Tell them one thing about your day that you would normally skip over. Let them into the ordinary.'},
{id:'d116',category:'daily',type:'spark',text:'What would you regret not saying if today were the last time you could say it?'},
{id:'d117',category:'daily',type:'spark',text:'Be kind in the moment when kindness does not come automatically. That is the moment that counts most.'},
{id:'d118',category:'daily',type:'spark',text:'What are you building today? Make sure your actions match the answer.'},
{id:'d119',category:'daily',type:'spark',text:'Love today like you understand what you have. Because you do.'},
{id:'d120',category:'daily',type:'spark',text:'Begin again today. You always can. You always can.'},
// ── MARRIAGE (80) ────────────────────────────────────────────────────────────
{id:'m1',category:'marriage',type:'advice',text:'Marriage is not the destination. It is the beginning of a longer, harder, more beautiful road. The couples who understand this go in with the right expectations.',author:'Loving Better'},
{id:'m2',category:'marriage',type:'quote',text:'The preparation matters more than the wedding. Everything you do now -- the conversations, the counselling, the honesty -- is the foundation. The foundation determines everything.',author:'Loving Better'},
{id:'m3',category:'marriage',type:'spark',text:'Do not rush past the preparation to get to the ceremony. The preparation is the real work.'},
{id:'m4',category:'marriage',type:'advice',text:'Have the money conversation -- all of it. The income, the debts, the obligations, the different relationships with spending. If you cannot have that conversation before marriage, you will have it after -- under worse conditions.',author:'Loving Better'},
{id:'m5',category:'marriage',type:'quote',text:'A marriage built on what you felt at the beginning is fragile. A marriage built on who you have chosen to become is strong.',author:'Loving Better'},
{id:'m6',category:'marriage',type:'spark',text:'What does a good marriage look like to both of you -- specifically? Have that conversation.'},
{id:'m7',category:'marriage',type:'advice',text:'Before marriage, discuss: what are we each carrying from our families of origin that we want to keep? What are we determined to leave behind? This conversation prevents the unconscious repetition of old patterns.',author:'Loving Better'},
{id:'m8',category:'marriage',type:'quote',text:'The wedding is one day. The marriage is every day after. Invest accordingly.',author:'Loving Better'},
{id:'m9',category:'marriage',type:'spark',text:'Marriage does not fix what is broken between you. It amplifies everything -- the good and the unaddressed.'},
{id:'m10',category:'marriage',type:'advice',text:'Choose a church home together before marriage. Spiritual unity is not an assumption -- it is a decision that needs to be made consciously and maintained actively.',author:'Loving Better'},
{id:'m11',category:'marriage',type:'quote',text:'The couples with the strongest marriages are not the ones who had the easiest courtships. They are the ones who built the most honest foundations.',author:'Loving Better'},
{id:'m12',category:'marriage',type:'spark',text:'What do you need to heal before you marry? Name it. Address it. Now.'},
{id:'m13',category:'marriage',type:'advice',text:'Premarital counselling is not for couples who have problems. It is for couples who want to be prepared. Go before you need to go, not after.',author:'Loving Better'},
{id:'m14',category:'marriage',type:'quote',text:'Marriage will require you to choose each other in seasons when you do not feel like it. Practise choosing each other now -- in the difficult conversations, in the moments of inconvenience.',author:'Loving Better'},
{id:'m15',category:'marriage',type:'spark',text:'What kind of home do you want to build together? Discuss the values, not just the furniture.'},
{id:'m16',category:'marriage',type:'advice',text:'Talk about children before marriage -- not abstractly but specifically. How many. Parenting philosophy. Discipline approach. What faith looks like for them. Fundamental misalignment here needs to be known now.',author:'Loving Better'},
{id:'m17',category:'marriage',type:'quote',text:'The vows you make on your wedding day are a beginning -- the daily recommitment to them is the marriage.',author:'Loving Better'},
{id:'m18',category:'marriage',type:'spark',text:'A great marriage is not found. It is built -- by two people who refuse to stop building.'},
{id:'m19',category:'marriage',type:'advice',text:'Do not marry someone hoping they will change. Marry someone whose current character -- not their potential, not their promises -- is what you can build a life with.',author:'Loving Better'},
{id:'m20',category:'marriage',type:'quote',text:'The greatest gift you can give each other is two whole, growing, self-aware individuals who choose to share a life.',author:'Loving Better'},
{id:'m21',category:'marriage',type:'spark',text:'Write a letter to the person you will be on your 10th wedding anniversary. What will you wish you had done today?'},
{id:'m22',category:'marriage',type:'advice',text:'Know each other\'s families well before marriage. You marry into a system, not just a person. Understanding the system helps you navigate it.',author:'Loving Better'},
{id:'m23',category:'marriage',type:'quote',text:'The couple that prays together, communicates honestly, and refuses to let problems go unaddressed -- that is the couple that lasts.',author:'Loving Better'},
{id:'m24',category:'marriage',type:'spark',text:'What agreements do you need to have about household roles, finances, and family before you marry? Have them now.'},
{id:'m25',category:'marriage',type:'advice',text:'Build the friendship. The romantic relationship will have seasons of intensity and seasons of ordinariness. The friendship sustains it through both.',author:'Loving Better'},
{id:'m26',category:'marriage',type:'quote',text:'Marriage is not where love ends. It is where love matures -- past the feelings and into the daily decision.',author:'Loving Better'},
{id:'m27',category:'marriage',type:'spark',text:'Can you have the financial conversation fully and honestly? Do it before you say the vows, not after.'},
{id:'m28',category:'marriage',type:'advice',text:'The hardest thing about marriage is not the big crises. It is sustaining intimacy and friendship through the relentless ordinariness of daily life. Build habits now that will sustain you then.',author:'Loving Better'},
{id:'m29',category:'marriage',type:'quote',text:'A home is not built from bricks. It is built from the quality of the daily life inside it.',author:'Loving Better'},
{id:'m30',category:'marriage',type:'spark',text:'What would you want your children to see when they watch how you love each other?'},
{id:'m31',category:'marriage',type:'advice',text:'Marriage requires that you extend grace to the same person, repeatedly, over years. That is not a burden -- it is the project. The capacity for that grace is what you are developing right now.',author:'Loving Better'},
{id:'m32',category:'marriage',type:'quote',text:'The couple who knows how to repair is the couple who will last. Learn repair before you need it most.',author:'Loving Better'},
{id:'m33',category:'marriage',type:'spark',text:'What does love look like in your household specifically? Not in theory. Name it.'},
{id:'m34',category:'marriage',type:'advice',text:'Establish early how you will handle disagreements about money, parenting, and in-laws. These are the three areas most likely to test a marriage. Have the agreements now.',author:'Loving Better'},
{id:'m35',category:'marriage',type:'quote',text:'A marriage where both people feel seen and known is a marriage that can withstand almost anything.',author:'Loving Better'},
{id:'m36',category:'marriage',type:'spark',text:'What would "us at our best" look like ten years from now? Describe it together.'},
{id:'m37',category:'marriage',type:'advice',text:'Date each other after you marry. The relationship that launched in pursuit must not end in assumption. Keep pursuing each other.',author:'Loving Better'},
{id:'m38',category:'marriage',type:'quote',text:'Every year of marriage that both people have grown individually is a year the marriage itself has grown.',author:'Loving Better'},
{id:'m39',category:'marriage',type:'spark',text:'What is one thing you are committed to bringing to this marriage -- not someday, but starting now?'},
{id:'m40',category:'marriage',type:'advice',text:'The vow "to love and to cherish" means something specific: that the other person feels valued and honoured, not just tolerated or provided for. Know what cherished feels like for your partner.',author:'Loving Better'},
{id:'m41',category:'marriage',type:'quote',text:'Choosing the same person every day for the rest of your life is the most audacious act of faith available to a human being.',author:'Loving Better'},
{id:'m42',category:'marriage',type:'spark',text:'What makes this person the right person for you -- beyond the feelings, in the specific character?'},
{id:'m43',category:'marriage',type:'advice',text:'Make a decision together about who you will go to when the marriage is struggling. A trusted pastor, a counsellor, a mentor couple. Having that plan before the crisis is wisdom.',author:'Loving Better'},
{id:'m44',category:'marriage',type:'quote',text:'The most romantic thing two people can do is to become people who are actually capable of sustaining what they are promising.',author:'Loving Better'},
{id:'m45',category:'marriage',type:'spark',text:'Have you both been fully honest about your pasts -- the things that shaped you, the things that still affect you?'},
{id:'m46',category:'marriage',type:'advice',text:'Know your roles. Not as rigid prescriptions but as conscious choices. Who manages the budget? Who takes the lead on what? Undefined roles create conflict. Agreed roles create peace.',author:'Loving Better'},
{id:'m47',category:'marriage',type:'quote',text:'A marriage without communication is like a house without windows. Things decay faster in the dark.',author:'Loving Better'},
{id:'m48',category:'marriage',type:'spark',text:'What does it mean to you to honour your partner? Name three specific things.'},
{id:'m49',category:'marriage',type:'advice',text:'Protect your marriage from the outside. Not by hiding it but by being intentional about what you bring into the shared space -- what you watch, who you confide in, where your emotional energy goes.',author:'Loving Better'},
{id:'m50',category:'marriage',type:'quote',text:'Marriage magnifies. Whatever is good between you becomes more visible. Whatever is unaddressed becomes louder. Go in with as little unaddressed as possible.',author:'Loving Better'},
{id:'m51',category:'marriage',type:'spark',text:'What conversation would change everything between you if you had it fully and honestly before the wedding?'},
{id:'m52',category:'marriage',type:'advice',text:'Create traditions together before you marry. Small rituals that belong to just the two of you. These become the culture of your marriage and the foundation your children will build on.',author:'Loving Better'},
{id:'m53',category:'marriage',type:'quote',text:'Two people who have survived the difficult season before marriage know more about the relationship than two people who have only experienced the easy one.',author:'Loving Better'},
{id:'m54',category:'marriage',type:'spark',text:'Do you know your partner\'s love language? Are you speaking it? Daily?'},
{id:'m55',category:'marriage',type:'advice',text:'The question is not "do we have problems?" Every couple has problems. The question is "do we have the tools and the willingness to address them?" That is what you are building right now.',author:'Loving Better'},
{id:'m56',category:'marriage',type:'quote',text:'A couple that knows how to fight well and forgive fully is a couple that is ready for marriage.',author:'Loving Better'},
{id:'m57',category:'marriage',type:'spark',text:'What is one expectation you have about marriage that you have never said out loud to your partner?'},
{id:'m58',category:'marriage',type:'advice',text:'Marriage is not a solution to loneliness, financial stress, or personal pain. It will amplify all three if those things are not addressed first. Do the work now.',author:'Loving Better'},
{id:'m59',category:'marriage',type:'quote',text:'The season before marriage is the season to become the partner you want to bring into it. Use it.',author:'Loving Better'},
{id:'m60',category:'marriage',type:'spark',text:'Are you choosing each other daily? The daily choosing is the practice for the lifetime choosing.'},
{id:'m61',category:'marriage',type:'advice',text:'Learn each other\'s triggers before marriage so you can navigate them together, not discover them in crisis. Knowing what breaks the other person apart and choosing gentleness in those places -- that is love.',author:'Loving Better'},
{id:'m62',category:'marriage',type:'quote',text:'The most powerful thing you can bring into a marriage is not a ring or a ceremony. It is the work you have already done on yourself.',author:'Loving Better'},
{id:'m63',category:'marriage',type:'spark',text:'What does forgiveness look like in this relationship right now? It will need to look the same inside marriage -- practise it.'},
{id:'m64',category:'marriage',type:'advice',text:'Discuss how you will handle extended family -- visits, expectations, financial requests, involvement in your decisions. Undefined boundaries become sources of conflict. Defined ones become sources of peace.',author:'Loving Better'},
{id:'m65',category:'marriage',type:'quote',text:'A marriage is not made in the ceremony. It is made in every conversation after it.',author:'Loving Better'},
{id:'m66',category:'marriage',type:'spark',text:'What is one area where you know you need to grow before you are ready to be a spouse?'},
{id:'m67',category:'marriage',type:'advice',text:'Agree on what "needing help" looks like and remove the shame from it. Every couple will need outside help at some point. The ones who agreed to seek it early fare better than the ones who wait until everything breaks.',author:'Loving Better'},
{id:'m68',category:'marriage',type:'quote',text:'The couple who builds together, prays together, and is honest together will outlast the couple who only feels together.',author:'Loving Better'},
{id:'m69',category:'marriage',type:'spark',text:'Name three qualities about your partner that make them the right person to build a life with.'},
{id:'m70',category:'marriage',type:'advice',text:'The patterns you establish in the first year of marriage tend to persist. Be intentional about which habits you build into that first year -- date nights, prayer together, financial reviews, check-ins.',author:'Loving Better'},
{id:'m71',category:'marriage',type:'quote',text:'Marriage is the daily practice of choosing one person as the most important relationship in your life -- and acting like it.',author:'Loving Better'},
{id:'m72',category:'marriage',type:'spark',text:'What does the life you want to build together actually look like day to day? Describe a Tuesday.'},
{id:'m73',category:'marriage',type:'advice',text:'Do not take each other for granted after the wedding. The pursuit that won the heart must continue to hold it. Keep doing the things that made the other person feel chosen.',author:'Loving Better'},
{id:'m74',category:'marriage',type:'quote',text:'The best marriages are the ones where both people feel like the luckier one.',author:'Loving Better'},
{id:'m75',category:'marriage',type:'spark',text:'What vows do you actually want to make -- not the traditional ones, but the specific promises that matter most to you?'},
{id:'m76',category:'marriage',type:'advice',text:'Protect the marriage from the busyness of life. Set aside time that belongs only to each other -- sacred, consistent, protected from the demands of work, family, and obligation.',author:'Loving Better'},
{id:'m77',category:'marriage',type:'quote',text:'The couple who treats the marriage as the most important relationship in their life -- and acts accordingly -- is the couple that builds something worth having.',author:'Loving Better'},
{id:'m78',category:'marriage',type:'spark',text:'If you married this person tomorrow, what would you most wish you had done differently in this season?'},
{id:'m79',category:'marriage',type:'advice',text:'A wedding is public. A marriage is private. The private work -- the conversations, the growth, the daily choices -- is what the public ceremony is pointing toward. Do that work.',author:'Loving Better'},
{id:'m80',category:'marriage',type:'quote',text:'Two people who are both growing toward God will find themselves growing toward each other.',author:'Loving Better'},
// ── FORGIVENESS (60) ─────────────────────────────────────────────────────────
{id:'fg1',category:'forgiveness',type:'advice',text:'Forgiveness is not a feeling that arrives when the conditions are right. It is a decision made in the absence of the feeling, as an act of will and faith.',author:'Loving Better'},
{id:'fg2',category:'forgiveness',type:'quote',text:'You cannot forgive someone and keep the evidence against them equally available. Forgiveness means the account is closed, not suspended.',author:'Loving Better'},
{id:'fg3',category:'forgiveness',type:'spark',text:'What are you still carrying that was meant to be released months ago? Today is the day.'},
{id:'fg4',category:'forgiveness',type:'advice',text:'Forgiveness without accountability is enablement. You can forgive someone and simultaneously require that they demonstrate changed behaviour. The two things are not in conflict.',author:'Loving Better'},
{id:'fg5',category:'forgiveness',type:'quote',text:'Unforgiveness is drinking poison and waiting for the other person to die. The person most hurt by what you hold is you.',author:'Loving Better'},
{id:'fg6',category:'forgiveness',type:'spark',text:'Releasing someone from a debt does not mean you forget what was owed. It means you stop collecting.'},
{id:'fg7',category:'forgiveness',type:'advice',text:'The hardest person to forgive is sometimes yourself. For what you did. For what you allowed. For how long it took you. Give yourself the same grace you are extending to others.',author:'Loving Better'},
{id:'fg8',category:'forgiveness',type:'quote',text:'Forgiveness is not the same as reconciliation. You can forgive someone and still require that they earn back the access they lost.',author:'Loving Better'},
{id:'fg9',category:'forgiveness',type:'spark',text:'Forgiveness is a process, not an event. Begin the process today even if you cannot complete it.'},
{id:'fg10',category:'forgiveness',type:'advice',text:'When you bring up a forgiven thing in a new argument, you reveal that the forgiveness was incomplete. Complete it -- or acknowledge that it was not yet given -- and address it properly.',author:'Loving Better'},
{id:'fg11',category:'forgiveness',type:'quote',text:'The ability to forgive is the ability to stop letting the past have more power than the present.',author:'Loving Better'},
{id:'fg12',category:'forgiveness',type:'spark',text:'What would change in this relationship today if the debt were genuinely cancelled?'},
{id:'fg13',category:'forgiveness',type:'advice',text:'Forgiveness does not happen all at once. You may forgive the same thing thirty times before it stops having power. That is not weakness -- that is how the process works. Keep forgiving.',author:'Loving Better'},
{id:'fg14',category:'forgiveness',type:'quote',text:'Asking for forgiveness requires humility. Granting it requires generosity. Both are acts of love.',author:'Loving Better'},
{id:'fg15',category:'forgiveness',type:'spark',text:'Name what you are forgiving. Vague forgiveness does not reach the specific thing that broke.'},
{id:'fg16',category:'forgiveness',type:'advice',text:'A genuine apology has three parts: what I did, why it was wrong, and what I am going to do differently. Anything shorter is incomplete.',author:'Loving Better'},
{id:'fg17',category:'forgiveness',type:'quote',text:'When someone shows you who they are -- changed -- believe them. Change is real. It just takes time to verify.',author:'Loving Better'},
{id:'fg18',category:'forgiveness',type:'spark',text:'Forgive them for the specific thing. Not the general. For the specific thing that hurt you.'},
{id:'fg19',category:'forgiveness',type:'advice',text:'Resentment feels like power but it is actually paralysis. The person who forgives is the one who gets to move forward. The person who holds on is the one who stays stuck.',author:'Loving Better'},
{id:'fg20',category:'forgiveness',type:'quote',text:'The measure of a person is not how they respond when they are right. It is how they respond when they have been genuinely wrong.',author:'Loving Better'},
{id:'fg21',category:'forgiveness',type:'spark',text:'Can you separate the person from what they did? Hate what was done. Choose the person.'},
{id:'fg22',category:'forgiveness',type:'advice',text:'Some things take longer to forgive than others -- and that is not a sign of weak character. It is a sign of a significant wound. Give the process the time it requires. Just do not let it stop.',author:'Loving Better'},
{id:'fg23',category:'forgiveness',type:'quote',text:'Forgiveness is not the end of accountability. It is the beginning of a new chapter that accountability helps write correctly.',author:'Loving Better'},
{id:'fg24',category:'forgiveness',type:'spark',text:'The apology you have been waiting for may never come. Can you forgive without it? Your healing may depend on the answer.'},
{id:'fg25',category:'forgiveness',type:'advice',text:'When you receive a genuine apology, receive it genuinely. Do not punish an honest apology with dismissal. That teaches the other person that honesty does not get rewarded -- and they will stop offering it.',author:'Loving Better'},
{id:'fg26',category:'forgiveness',type:'quote',text:'Forgiveness does not make what happened okay. It makes your life after it okay.',author:'Loving Better'},
{id:'fg27',category:'forgiveness',type:'spark',text:'What would it cost you to forgive this fully? What would it cost you not to?'},
{id:'fg28',category:'forgiveness',type:'advice',text:'There is a difference between forgiving and pretending nothing happened. You can fully forgive while still naming the impact, still requiring changed behaviour, still protecting yourself from repeat harm.',author:'Loving Better'},
{id:'fg29',category:'forgiveness',type:'quote',text:'Bitterness is a prison that only you can build and only you can leave.',author:'Loving Better'},
{id:'fg30',category:'forgiveness',type:'spark',text:'What would you feel if you woke up tomorrow and the thing you are carrying was simply gone?'},
{id:'fg31',category:'forgiveness',type:'advice',text:'Forgiveness in a relationship is not a single event that ends the matter. It is a posture -- a daily decision to not let the past debt accrue interest.',author:'Loving Better'},
{id:'fg32',category:'forgiveness',type:'quote',text:'The wound you refuse to forgive is the wound you keep reopening.',author:'Loving Better'},
{id:'fg33',category:'forgiveness',type:'spark',text:'You do not have to feel ready to forgive. You just have to decide to. The feeling follows the decision.'},
{id:'fg34',category:'forgiveness',type:'advice',text:'Do not confuse forgiving with forgetting your discernment. Forgiveness does not mean you stop paying attention to behaviour. It means you stop letting past behaviour pre-determine current reality.',author:'Loving Better'},
{id:'fg35',category:'forgiveness',type:'quote',text:'The grace you have received is the same grace you are being asked to give. Remember what it felt like to need it.',author:'Loving Better'},
{id:'fg36',category:'forgiveness',type:'spark',text:'Tell them you forgive them. Even if you have said it before. Say it again, specifically, today.'},
{id:'fg37',category:'forgiveness',type:'advice',text:'When you struggle to forgive, ask: what am I afraid will happen if I let this go? The fear underneath the unforgiveness is usually the real thing to address.',author:'Loving Better'},
{id:'fg38',category:'forgiveness',type:'quote',text:'A person who learns to forgive freely becomes the kind of partner who is safe to make mistakes with -- and that safety is one of the most valuable things in a relationship.',author:'Loving Better'},
{id:'fg39',category:'forgiveness',type:'spark',text:'What would you need to believe about yourself to stop needing their mistakes to define them?'},
{id:'fg40',category:'forgiveness',type:'advice',text:'Forgiveness is not trust. Forgiving does not mean you automatically trust again. Trust is rebuilt separately, through time and evidence. Do not conflate the two.',author:'Loving Better'},
{id:'fg41',category:'forgiveness',type:'quote',text:'Every time you choose to forgive, you are choosing the future over the past. That is always the right choice.',author:'Loving Better'},
{id:'fg42',category:'forgiveness',type:'spark',text:'What does the God you believe in say about forgiveness? Are you living by that?'},
{id:'fg43',category:'forgiveness',type:'advice',text:'The couple that has learned to forgive quickly is the couple that fights fair. The speed of the forgiveness determines the depth of the damage done in the meantime.',author:'Loving Better'},
{id:'fg44',category:'forgiveness',type:'quote',text:'The person you cannot forgive has power over you. Taking that power back is the act of forgiveness.',author:'Loving Better'},
{id:'fg45',category:'forgiveness',type:'spark',text:'What would you say to them if you were completely free from everything they have ever done? Say that.'},
{id:'fg46',category:'forgiveness',type:'advice',text:'Forgiveness is also about what you say to yourself about the person after you have forgiven them. Stop replaying the story of what they did in a way that keeps the wound fresh.',author:'Loving Better'},
{id:'fg47',category:'forgiveness',type:'quote',text:'You do not have to understand why they did it to forgive them for it. Understanding is a gift. Forgiveness is a decision.',author:'Loving Better'},
{id:'fg48',category:'forgiveness',type:'spark',text:'Is there something you have said you forgave but have not actually released? Be honest.'},
{id:'fg49',category:'forgiveness',type:'advice',text:'When asking for forgiveness, do not explain yourself so much that you talk the other person out of giving it. Say what you did, say why it was wrong, say what you will do differently. Then stop talking and let them process.',author:'Loving Better'},
{id:'fg50',category:'forgiveness',type:'quote',text:'The act of forgiving is one of the most creative things a human being can do. You are choosing what happens next instead of what happened last.',author:'Loving Better'},
{id:'fg51',category:'forgiveness',type:'spark',text:'What if forgiveness was not about them at all, but entirely about who you want to become?'},
{id:'fg52',category:'forgiveness',type:'advice',text:'Receiving forgiveness also requires something: genuine acknowledgement of what was done, not just relief that it is over. Do not skip past the reckoning into the comfort of forgiveness.',author:'Loving Better'},
{id:'fg53',category:'forgiveness',type:'quote',text:'A relationship where both people know they can make mistakes and be forgiven -- that is a relationship where both people can grow.',author:'Loving Better'},
{id:'fg54',category:'forgiveness',type:'spark',text:'Who in this relationship needs to hear "I forgive you" from you today?'},
{id:'fg55',category:'forgiveness',type:'advice',text:'Chronic unforgiveness in a relationship creates a culture of walking on eggshells. When both people know that mistakes will be held against them indefinitely, both people stop taking the risks that love requires.',author:'Loving Better'},
{id:'fg56',category:'forgiveness',type:'quote',text:'Every forgiveness you give makes you more capable of giving the next one. It is a muscle. Train it.',author:'Loving Better'},
{id:'fg57',category:'forgiveness',type:'spark',text:'What is the smallest thing you can forgive today that you have been holding onto? Start there.'},
{id:'fg58',category:'forgiveness',type:'advice',text:'Sometimes the thing most in need of forgiveness is not what the other person did but the gap between what you hoped they would be and who they actually are. That disappointment is real. Forgive it.',author:'Loving Better'},
{id:'fg59',category:'forgiveness',type:'quote',text:'Choose forgiveness not because it is deserved but because you deserve peace.',author:'Loving Better'},
{id:'fg60',category:'forgiveness',type:'spark',text:'Forgive them out loud. Not in your head. Out loud. Let them hear it. Let it be real.'},
// ── GROWTH (60) ──────────────────────────────────────────────────────────────
{id:'g1',category:'growth',type:'advice',text:'The version of you that this relationship is asking you to become is more whole, more honest, and more capable of love than the version you brought into it. The difficulty is the formation.',author:'Loving Better'},
{id:'g2',category:'growth',type:'quote',text:'You cannot grow in a relationship without being honest about where you actually are. Growth begins with an accurate diagnosis.',author:'Loving Better'},
{id:'g3',category:'growth',type:'spark',text:'What is one specific thing you are working on becoming? Name it. Then do one thing toward it today.'},
{id:'g4',category:'growth',type:'advice',text:'Both people must be growing simultaneously. A relationship cannot carry one stationary person and one growing person for long. The growing partner eventually outgrows the relationship. Grow together.',author:'Loving Better'},
{id:'g5',category:'growth',type:'quote',text:'The work you do on yourself between the hard conversations is what shows up in them.',author:'Loving Better'},
{id:'g6',category:'growth',type:'spark',text:'What habit would most change this relationship if you developed it? Start today.'},
{id:'g7',category:'growth',type:'advice',text:'Growth in a relationship is not about becoming someone new. It is about shedding the parts of yourself that are incompatible with loving well -- the fear, the avoidance, the pride, the need to be right.',author:'Loving Better'},
{id:'g8',category:'growth',type:'quote',text:'The best partner you can be is a whole person. Invest in becoming whole.',author:'Loving Better'},
{id:'g9',category:'growth',type:'spark',text:'What are you reading, learning, or practising that makes you better at love?'},
{id:'g10',category:'growth',type:'advice',text:'Emotional intelligence is learnable. The ability to name what you feel, regulate it under pressure, and respond thoughtfully rather than reactively -- all of this can be developed with intention.',author:'Loving Better'},
{id:'g11',category:'growth',type:'quote',text:'The most honest thing you can say to a partner is: "I am working on this specific thing because I want to love you better."',author:'Loving Better'},
{id:'g12',category:'growth',type:'spark',text:'Where were you one year ago in this relationship? Where are you now? What changed?'},
{id:'g13',category:'growth',type:'advice',text:'Do not wait until you have completely changed to begin showing your partner that you are changing. Show the process. Let them see the work. That is far more compelling than a completed transformation announced without evidence.',author:'Loving Better'},
{id:'g14',category:'growth',type:'quote',text:'The relationship is the mirror. What you see reflected in the other person\'s responses to you tells you something important about who you are right now.',author:'Loving Better'},
{id:'g15',category:'growth',type:'spark',text:'Ask your partner: what is one thing you have noticed me doing better recently? Their answer will show you your growth.'},
{id:'g16',category:'growth',type:'advice',text:'Accountability without self-compassion produces shame, not growth. Hold yourself responsible for your patterns while also giving yourself the grace to be in process. Both are required.',author:'Loving Better'},
{id:'g17',category:'growth',type:'quote',text:'Who you are in five years will be determined largely by the conversations you are willing to have today.',author:'Loving Better'},
{id:'g18',category:'growth',type:'spark',text:'What is the hardest thing about yourself to acknowledge? Acknowledging it is the first step toward changing it.'},
{id:'g19',category:'growth',type:'advice',text:'Read. Pray. Reflect. Seek counsel. Growth does not happen in isolation -- it requires input from outside yourself. What are you feeding your mind and spirit right now?',author:'Loving Better'},
{id:'g20',category:'growth',type:'quote',text:'Every version of yourself that chooses love over comfort, honesty over ease -- that version is the one worth becoming.',author:'Loving Better'},
{id:'g21',category:'growth',type:'spark',text:'The person you need to become to have the relationship you want -- what specifically does that person do differently?'},
{id:'g22',category:'growth',type:'advice',text:'Do not outsource your growth to the relationship. The relationship can be a catalyst, but the work belongs to you -- in private, in prayer, in the daily choices no one else can see.',author:'Loving Better'},
{id:'g23',category:'growth',type:'quote',text:'The most generous thing you can bring to a relationship is a growing, self-aware, emotionally honest version of yourself.',author:'Loving Better'},
{id:'g24',category:'growth',type:'spark',text:'Progress is not perfection. One better choice today is growth.'},
{id:'g25',category:'growth',type:'advice',text:'Track your growth. Look back at who you were six months ago in this relationship. Notice what has changed. Name it. Celebrate it. Then look at what still needs to.',author:'Loving Better'},
{id:'g26',category:'growth',type:'quote',text:'Difficulty in a relationship is not a sign that something is wrong. It is often a sign that something important is being formed.',author:'Loving Better'},
{id:'g27',category:'growth',type:'spark',text:'What pattern of yours has this relationship revealed that you need to change?'},
{id:'g28',category:'growth',type:'advice',text:'The version of you that you want to bring into marriage -- that version is built in the choices you make right now, in this season, before the ceremony.',author:'Loving Better'},
{id:'g29',category:'growth',type:'quote',text:'Personal growth is not selfish when it makes you more capable of loving the people in your life.',author:'Loving Better'},
{id:'g30',category:'growth',type:'spark',text:'What would you commit to changing if you knew it would save this relationship? Change it anyway.'},
{id:'g31',category:'growth',type:'advice',text:'The first question in any conflict should not be "who is right?" It should be "what is being revealed about me in how I am responding to this?" That question changes everything.',author:'Loving Better'},
{id:'g32',category:'growth',type:'quote',text:'A person who cannot name what they feel cannot communicate what they need. Name your feelings first -- to yourself, then to your partner.',author:'Loving Better'},
{id:'g33',category:'growth',type:'spark',text:'What does the version of you that you most want to be do differently in this relationship?'},
{id:'g34',category:'growth',type:'advice',text:'Stop waiting to be different before you start doing differently. Change happens through action, not through waiting to feel ready. Act your way into a new way of being.',author:'Loving Better'},
{id:'g35',category:'growth',type:'quote',text:'The couple who grows individually also grows together. Personal growth and relational growth are not in competition.',author:'Loving Better'},
{id:'g36',category:'growth',type:'spark',text:'What is one compliment you have been given about your character that you have not yet fully believed about yourself?'},
{id:'g37',category:'growth',type:'advice',text:'Be as generous in your assessment of your own growth as you want your partner to be. Do not only see what you have not yet changed. Also see what you have.',author:'Loving Better'},
{id:'g38',category:'growth',type:'quote',text:'Every honest conversation you have in this relationship is growing your capacity for intimacy. That capacity is one of the most valuable things you can develop.',author:'Loving Better'},
{id:'g39',category:'growth',type:'spark',text:'What is one thing you have said you would change that you have not yet started? What is stopping you?'},
{id:'g40',category:'growth',type:'advice',text:'Growth requires discomfort. If you are not occasionally uncomfortable in the work you are doing on yourself, you are probably not doing the work. The discomfort is the signal that you are in the right territory.',author:'Loving Better'},
{id:'g41',category:'growth',type:'quote',text:'You are not behind. You are becoming. There is always more time to choose to grow than you think.',author:'Loving Better'},
{id:'g42',category:'growth',type:'spark',text:'Name one area where you have genuinely grown in this relationship. Celebrate that.'},
{id:'g43',category:'growth',type:'advice',text:'Celebrate growth in your partner even when it is slow. When they do something differently -- even imperfectly -- name it. "I noticed you did that differently. That meant something to me." That kind of acknowledgement accelerates growth.',author:'Loving Better'},
{id:'g44',category:'growth',type:'quote',text:'The capacity to change is one of the most attractive things about a person. It signals that they are choosing to become rather than accepting what they already are.',author:'Loving Better'},
{id:'g45',category:'growth',type:'spark',text:'What conversation would most grow you right now -- the one you are most avoiding?'},
{id:'g46',category:'growth',type:'advice',text:'Growth in emotional availability looks like this: noticing when you are withdrawing and choosing to stay instead. Noticing when you are avoiding and choosing to speak instead. One better choice, repeated.',author:'Loving Better'},
{id:'g47',category:'growth',type:'quote',text:'You cannot grow toward someone you are hiding from. Show yourself fully. Let the relationship grow in response to who you actually are.',author:'Loving Better'},
{id:'g48',category:'growth',type:'spark',text:'What does the best version of this relationship feel like? What do you need to grow into to make that possible?'},
{id:'g49',category:'growth',type:'advice',text:'Seek wisdom from couples who have built what you want to build. Not from those who have what you currently have -- from those who are further along. Ask them what they know now that they wish they had known earlier.',author:'Loving Better'},
{id:'g50',category:'growth',type:'quote',text:'The relationship you have is the result of who you both have been. The relationship you want is the result of who you both choose to become.',author:'Loving Better'},
{id:'g51',category:'growth',type:'spark',text:'What would it mean to take full responsibility -- not blame, responsibility -- for your role in where this relationship currently is?'},
{id:'g52',category:'growth',type:'advice',text:'The most dangerous kind of non-growth is the kind that looks like growth. Performing change is not change. Check your actual behaviour, not your stated intentions.',author:'Loving Better'},
{id:'g53',category:'growth',type:'quote',text:'Every person you are in relationship with is showing you something about yourself. Pay attention to what this one is showing you.',author:'Loving Better'},
{id:'g54',category:'growth',type:'spark',text:'If your future children could see how you are loving each other right now, what would you want them to see?'},
{id:'g55',category:'growth',type:'advice',text:'Make time for solitude. Not to escape the relationship but to return to yourself -- to check in on your own state, your own growth, your own needs. From a full and honest inner life you can love more freely.',author:'Loving Better'},
{id:'g56',category:'growth',type:'quote',text:'The willingness to be wrong and to change in response to being wrong -- that is the foundation of all growth.',author:'Loving Better'},
{id:'g57',category:'growth',type:'spark',text:'What is one thing about yourself that you accept but do not have to? What would changing it make possible?'},
{id:'g58',category:'growth',type:'advice',text:'Journal. Even briefly. The act of writing what you are feeling and what you are learning gives your growth a shape. Shaped growth is more sustainable than growth you are just hoping is happening.',author:'Loving Better'},
{id:'g59',category:'growth',type:'quote',text:'You are not the same person you were when this relationship began. Neither are they. Keep discovering who you both are becoming.',author:'Loving Better'},
{id:'g60',category:'growth',type:'spark',text:'Begin. Right now. Whatever growth you have been deferring -- begin it now. The only time that exists is today.'},
{id:'l61',category:'love',type:'spark',text:'The relationship is not something that happens to you. It is something you create together, daily.'},
{id:'l62',category:'love',type:'quote',text:'Two people who keep choosing each other even in the seasons when choosing is hard -- that is the love worth building toward.',author:'Loving Better'},
{id:'l63',category:'love',type:'advice',text:'Do not confuse the absence of conflict with the presence of love. A quiet relationship can be one where people have stopped caring enough to engage. Fight for connection, not just peace.',author:'Loving Better'},
{id:'l64',category:'love',type:'spark',text:'What does your partner need most from you this week that you have not yet given?'},
{id:'l65',category:'love',type:'quote',text:'The most intimate thing two people can do is tell each other the truth.',author:'Loving Better'},
{id:'l66',category:'love',type:'advice',text:'Guard the friendship inside the romance. The romance ebbs and flows with seasons. The friendship, if cultivated, sustains everything.',author:'Loving Better'},
{id:'l67',category:'love',type:'spark',text:'Love is an action taken in the direction of someone else\'s wellbeing. Take one such action today.'},
{id:'l68',category:'love',type:'quote',text:'A relationship where both people feel safe to be imperfect is a relationship where both people can grow.',author:'Loving Better'},
{id:'l69',category:'love',type:'advice',text:'When was the last time you did something that surprised your partner -- not with a gift, but with an act of knowing? Knowing what they need before they say it, and providing it. That is love in its most fluent form.',author:'Loving Better'},
{id:'l70',category:'love',type:'spark',text:'What is one small thing they love that you could give them today for no reason at all?'},
{id:'l71',category:'love',type:'quote',text:'The love that is worth having requires you to be a person worth loving. Become that person.',author:'Loving Better'},
{id:'l72',category:'love',type:'advice',text:'Security in love is not the absence of uncertainty. It is the confidence that even in uncertain seasons, both people will keep choosing each other. Build that confidence through consistent action.',author:'Loving Better'},
{id:'l73',category:'love',type:'spark',text:'What does your love look like from their side? Ask them.'},
{id:'l74',category:'love',type:'quote',text:'The best relationships are the ones where both people are working on becoming better humans -- not just better partners.',author:'Loving Better'},
{id:'l75',category:'love',type:'advice',text:'Love requires that you tell the truth even when silence would be easier. Not to hurt -- but because a relationship built on comfortable untruths is not a real relationship.',author:'Loving Better'},
{id:'l76',category:'love',type:'spark',text:'Hold the door. Make the coffee. Say the name. Love in the specifics.'},
{id:'l77',category:'love',type:'quote',text:'The most ordinary moments of love are also the most sustaining ones.',author:'Loving Better'},
{id:'l78',category:'love',type:'advice',text:'Do not save your best self for the world and bring the leftovers home. The person who deserves your best self is the one you chose to share your life with.',author:'Loving Better'},
{id:'l79',category:'love',type:'spark',text:'What is one memory from your early time together that you both loved? Recreate some version of it today.'},
{id:'l80',category:'love',type:'quote',text:'Love built on truth is the only kind that lasts. Everything else is eventually exposed.',author:'Loving Better'},
{id:'l81',category:'love',type:'advice',text:'The relationship you have tomorrow is built by the choices you make today. Make today\'s choices worthy of tomorrow\'s relationship.',author:'Loving Better'},
{id:'l82',category:'love',type:'spark',text:'Notice something beautiful about them today. Name it. Out loud.'},
{id:'l83',category:'love',type:'quote',text:'When you find yourself cataloguing their faults, turn the list around. What are they cataloguing about you? And what would you want them to do with that list?',author:'Loving Better'},
{id:'l84',category:'love',type:'advice',text:'Love without honesty becomes performance. Honesty without love becomes cruelty. The work is holding both at once -- saying the true thing in a form that love shapes.',author:'Loving Better'},
{id:'l85',category:'love',type:'spark',text:'What does love ask of you today? Not what it gives you -- what it asks of you. Do that.'},
{id:'l86',category:'love',type:'quote',text:'To be loved fully is to be known fully -- and accepted anyway. Build toward that.',author:'Loving Better'},
{id:'l87',category:'love',type:'advice',text:'Protect your relationship from contempt with one practice: actively look for what you respect about your partner, daily. What you look for, you find. Look for the good.',author:'Loving Better'},
{id:'l88',category:'love',type:'spark',text:'Tell them something about themselves that you have been admiring silently for too long.'},
{id:'l89',category:'love',type:'quote',text:'Love is not blind. Real love sees everything -- and chooses anyway. That choosing is the love.',author:'Loving Better'},
{id:'l90',category:'love',type:'advice',text:'The relationship needs you present. Not the version of you that is planning tomorrow or replaying yesterday. The version that is here, now, with this person, in this moment.',author:'Loving Better'},
{id:'c81',category:'communication',type:'spark',text:'What is one thing your partner said last week that you want to revisit? Revisit it today.'},
{id:'c82',category:'communication',type:'quote',text:'Saying "I don\'t know" in a conversation is more honest and more useful than filling the silence with something untrue.',author:'Loving Better'},
{id:'c83',category:'communication',type:'advice',text:'Before you raise something difficult, ask: am I trying to be heard or am I trying to win? If you want to be heard, lead with the feeling. If you want to win, examine why.',author:'Loving Better'},
{id:'c84',category:'communication',type:'spark',text:'Practise receiving feedback today without defending. Just hear it. Just take it in.'},
{id:'c85',category:'communication',type:'quote',text:'The conversation that changes a relationship is almost never the comfortable one.',author:'Loving Better'},
{id:'c86',category:'communication',type:'advice',text:'When you say "I\'m fine" and you are not, you are not protecting the relationship -- you are creating a debt that will collect interest. Name what is actually true.',author:'Loving Better'},
{id:'c87',category:'communication',type:'spark',text:'Ask them about something they have been thinking about lately that has nothing to do with the two of you.'},
{id:'c88',category:'communication',type:'quote',text:'The best communication is not about saying everything you think. It is about saying the things that serve the relationship.',author:'Loving Better'},
{id:'c89',category:'communication',type:'advice',text:'Tone is not decoration -- it is content. The same words in a harsh tone and a gentle tone communicate entirely different things. Choose your tone as carefully as you choose your words.',author:'Loving Better'},
{id:'c90',category:'communication',type:'spark',text:'What is something you have been communicating through your behaviour that you have never said directly? Say it directly.'},
{id:'c91',category:'communication',type:'quote',text:'Every time you say the hard thing gently, you are training the relationship to be a safe place. Keep training it.',author:'Loving Better'},
{id:'c92',category:'communication',type:'advice',text:'Create a weekly ritual that invites honest sharing: a walk where you each say one thing that has been sitting with you. These rituals make the extraordinary ordinary -- and the ordinary extraordinary.',author:'Loving Better'},
{id:'c93',category:'communication',type:'spark',text:'Speak up earlier, softer. That is the whole formula.'},
{id:'c94',category:'communication',type:'quote',text:'When they stop telling you things, it is not because they have nothing to say. It is because they have learned that saying it costs more than it gives. Change what it costs.',author:'Loving Better'},
{id:'c95',category:'communication',type:'advice',text:'An unheard person eventually stops speaking. Make sure the person you love always feels heard -- not agreed with, not immediately fixed -- heard.',author:'Loving Better'},
{id:'c96',category:'communication',type:'spark',text:'What is the most important thing you could say to each other today? Say it.'},
{id:'c97',category:'communication',type:'quote',text:'The relationship gets stronger every time you choose the difficult conversation over the comfortable silence.',author:'Loving Better'},
{id:'c98',category:'communication',type:'advice',text:'When they raise something hard, the gift you can give is your full, unhurried attention. Not a quick fix. Not a counter-point. Just: I am here, I am listening, I want to understand.',author:'Loving Better'},
{id:'c99',category:'communication',type:'spark',text:'What do you most need your partner to understand about you right now? Have you told them?'},
{id:'c100',category:'communication',type:'quote',text:'Communication is the bridge between where you are and where you want to be in this relationship. Build it carefully.',author:'Loving Better'},
{id:'t51',category:'trust',type:'advice',text:'Trust is the oxygen of a relationship. When it is present you do not notice it. When it is absent, everything is a struggle. Tend it before it runs low.',author:'Loving Better'},
{id:'t52',category:'trust',type:'spark',text:'What would it look like to be more transparent with your partner today about what is actually going on inside you?'},
{id:'t53',category:'trust',type:'quote',text:'The person who tells you the truth even when it is hard to hear is the person who respects you most.',author:'Loving Better'},
{id:'t54',category:'trust',type:'advice',text:'When you catch yourself managing the truth -- shading it, softening it to the point of distortion, leaving the important parts out -- name it. Then give the full version.',author:'Loving Better'},
{id:'t55',category:'trust',type:'spark',text:'Do what you said you would do today. That is the whole assignment.'},
{id:'t56',category:'trust',type:'quote',text:'Trust is built in the moments when you do the right thing even though no one is checking.',author:'Loving Better'},
{id:'t57',category:'trust',type:'advice',text:'Create a culture of follow-through. When you say you will do something and you do it, your partner\'s nervous system relaxes a little. Do that enough times and the relaxation becomes security.',author:'Loving Better'},
{id:'t58',category:'trust',type:'spark',text:'What does your partner most need to be able to trust you with? Are you trustworthy in that area?'},
{id:'t59',category:'trust',type:'quote',text:'A reliable person is one of the rarest and most attractive things in the world. Become one.',author:'Loving Better'},
{id:'t60',category:'trust',type:'advice',text:'Never lie to spare the feelings of your partner in ways that will matter later. The short-term comfort of the managed truth is not worth the long-term cost of the discovered lie.',author:'Loving Better'},
{id:'h51',category:'healing',type:'advice',text:'If you are stuck in the same argument, the same wound, the same cycle -- it is not because you are broken. It is because the underlying issue has not been fully named and addressed. Name it.',author:'Loving Better'},
{id:'h52',category:'healing',type:'spark',text:'What is something you thought you had healed but that recently resurfaced? It deserves more attention.'},
{id:'h53',category:'healing',type:'quote',text:'The thing that broke between you is not proof that it cannot be rebuilt. It is proof of where the work needs to happen.',author:'Loving Better'},
{id:'h54',category:'healing',type:'advice',text:'Healing together requires regular honest check-ins: "How are we actually doing? Is there anything between us that needs to be addressed that we have been avoiding?" Ask. Then listen to the full answer.',author:'Loving Better'},
{id:'h55',category:'healing',type:'spark',text:'What would complete healing in this relationship look like? Describe it. Then work toward it.'},
{id:'h56',category:'healing',type:'quote',text:'Every time you choose to address something rather than avoid it, you are choosing your relationship\'s health over your own temporary comfort.',author:'Loving Better'},
{id:'h57',category:'healing',type:'advice',text:'The season of healing is not a detour from the relationship. It is the relationship -- in its most important form. Do not rush it. Do not skip it. Be in it fully.',author:'Loving Better'},
{id:'h58',category:'healing',type:'spark',text:'What one thing, fully addressed and resolved, would most change the quality of this relationship?'},
{id:'h59',category:'healing',type:'quote',text:'Real healing is evidenced by changed responses, not stated intentions. Watch what you actually do.',author:'Loving Better'},
{id:'h60',category:'healing',type:'advice',text:'If something keeps hurting you and you keep absorbing it rather than naming it, you are not being strong. You are building a wall, brick by silent brick. Say the thing.',author:'Loving Better'},
{id:'m81',category:'marriage',type:'advice',text:'The couple who builds habits of connection before marriage enters marriage with something most couples have to learn the hard way. Use this season well.',author:'Loving Better'},
{id:'m82',category:'marriage',type:'spark',text:'What conversation about your future together have you been putting off? Have it this week.'},
{id:'m83',category:'marriage',type:'quote',text:'Marriage is not a finish line. It is a starting line for the most important race of your life.',author:'Loving Better'},
{id:'m84',category:'marriage',type:'advice',text:'Before marriage, both people should know: what does this person do when they are under real pressure? You will find out inside marriage. Try to find out before.',author:'Loving Better'},
{id:'m85',category:'marriage',type:'spark',text:'What would you want your partner to say about you on your wedding day that is not yet fully true?'},
{id:'m86',category:'marriage',type:'quote',text:'A marriage where both people are growing is a marriage that gets better with time. Invest in each other\'s growth.',author:'Loving Better'},
{id:'m87',category:'marriage',type:'advice',text:'Discuss your exit strategy before marriage -- not because you plan to use it, but because couples who agree to seek help and stay and work through difficulty are the ones who last.',author:'Loving Better'},
{id:'m88',category:'marriage',type:'spark',text:'What is one fear you have about marriage that you have not shared with your partner?'},
{id:'m89',category:'marriage',type:'quote',text:'The wedding you plan in one day. The marriage you plan in every day before it.',author:'Loving Better'},
{id:'m90',category:'marriage',type:'advice',text:'Choose your person, then keep choosing them. The initial choice is a moment. The ongoing choice is the marriage.',author:'Loving Better'},
{id:'fg61',category:'forgiveness',type:'advice',text:'Forgiveness in a relationship is not a one-time act. It is a way of living with another person -- extending grace daily, releasing small debts before they compound into large ones.',author:'Loving Better'},
{id:'fg62',category:'forgiveness',type:'spark',text:'What is the one word that captures what you need to forgive right now? Just one. Start there.'},
{id:'fg63',category:'forgiveness',type:'quote',text:'The grace you give your partner today is the grace you will need from them tomorrow.',author:'Loving Better'},
{id:'fg64',category:'forgiveness',type:'advice',text:'Release the need to have been right about your worst assessment of your partner. You may have been right. Staying right about it costs you more than the rightness is worth.',author:'Loving Better'},
{id:'fg65',category:'forgiveness',type:'spark',text:'What would it feel like to go to sleep tonight with nothing held against them?'},
{id:'fg66',category:'forgiveness',type:'quote',text:'Forgiveness is not weakness. It is the most courageous thing you can do with pain.',author:'Loving Better'},
{id:'fg67',category:'forgiveness',type:'advice',text:'The act of forgiving out loud -- saying it directly to the person -- is different from forgiving in your heart alone. Both matter. The spoken version heals something in the relationship that the internal one cannot.',author:'Loving Better'},
{id:'fg68',category:'forgiveness',type:'spark',text:'Who taught you how to forgive? Is that a model worth following here?'},
{id:'fg69',category:'forgiveness',type:'quote',text:'Forgiveness is the decision to set yourself free from what was done to you.',author:'Loving Better'},
{id:'fg70',category:'forgiveness',type:'advice',text:'Forgive quickly and forgive completely. Not because the other person has earned it. Because the alternative -- carrying it -- is destroying something in you that you need for the relationship.',author:'Loving Better'},
{id:'g61',category:'growth',type:'advice',text:'The version of you that this relationship is asking you to become -- step into that version today. Not when you feel ready. Now.',author:'Loving Better'},
{id:'g62',category:'growth',type:'spark',text:'What have you been tolerating in yourself that you would not tolerate in your partner?'},
{id:'g63',category:'growth',type:'quote',text:'Personal growth is not about becoming someone different. It is about becoming more fully yourself -- the self that is capable of the love you want to give.',author:'Loving Better'},
{id:'g64',category:'growth',type:'advice',text:'The person who never asks for feedback never knows what they need to change. Ask your partner: "What is one thing I could do differently that would make a real difference to you?" Then do it.',author:'Loving Better'},
{id:'g65',category:'growth',type:'spark',text:'What is one thing you used to be that you no longer are -- and one thing you want to become that you are not yet?'},
{id:'g66',category:'growth',type:'quote',text:'Growth in love is not about loving more. It is about loving better -- with more skill, more patience, more specific attention.',author:'Loving Better'},
{id:'g67',category:'growth',type:'advice',text:'Stop comparing your growth to anyone else\'s. The only relevant comparison is between who you were and who you are becoming. Make that comparison daily and honestly.',author:'Loving Better'},
{id:'g68',category:'growth',type:'spark',text:'What would you need to stop doing to become the partner this relationship deserves?'},
{id:'g69',category:'growth',type:'quote',text:'The most important growth happens in the moments when staying the same would be easier.',author:'Loving Better'},
{id:'g70',category:'growth',type:'advice',text:'Name your patterns. Not to condemn yourself but to see them clearly enough to change them. You cannot change what you cannot name.',author:'Loving Better'},
{id:'d121',category:'daily',type:'spark',text:'What is the most loving thing you can do in the next ten minutes? Do that.'},
{id:'d122',category:'daily',type:'spark',text:'Today: less evaluating, more appreciating.'},
{id:'d123',category:'daily',type:'spark',text:'What would this day look like if you led with love from the first moment?'},
{id:'d124',category:'daily',type:'spark',text:'Make them laugh today. Just because.'},
{id:'d125',category:'daily',type:'spark',text:'One act of gentleness today -- in a moment when it does not come automatically.'},
{id:'d126',category:'daily',type:'spark',text:'What is something about them you have been taking for granted? Stop taking it for granted today.'},
{id:'d127',category:'daily',type:'spark',text:'Look them in the eyes when they talk today. Really look.'},
{id:'d128',category:'daily',type:'spark',text:'Tell them one specific thing you are grateful for about the way they love you.'},
{id:'d129',category:'daily',type:'spark',text:'What would they say they need most from you today? If you do not know, ask.'},
{id:'d130',category:'daily',type:'spark',text:'Be slow to anger today. Take the breath. Choose the response.'},
{id:'d131',category:'daily',type:'spark',text:'Bring them into one moment today that you would normally keep to yourself.'},
{id:'d132',category:'daily',type:'spark',text:'What is one thing you know about them that most people do not? Remind them that you see them.'},
{id:'d133',category:'daily',type:'spark',text:'Do something today that says: I was thinking about what you like, not what I like.'},
{id:'d134',category:'daily',type:'spark',text:'End the day with warmth. Whatever else happened -- warmth at the end.'},
{id:'d135',category:'daily',type:'spark',text:'Tell them: "I\'m on your side." Mean it.'},
{id:'d136',category:'daily',type:'spark',text:'What is one way you can make today easier for them?'},
{id:'d137',category:'daily',type:'spark',text:'Be present in the small moment today. Not the big gesture. The small moment.'},
{id:'d138',category:'daily',type:'spark',text:'What does love ask of you today? Not what it gives -- what it asks. Do that.'},
{id:'d139',category:'daily',type:'spark',text:'Create one moment of stillness together today. Just quiet. Just presence.'},
{id:'d140',category:'daily',type:'spark',text:'Say something kind about them to someone else today. Let it get back to them.'},
{id:'d141',category:'daily',type:'spark',text:'What is one thing they have been working on that you can acknowledge today?'},
{id:'d142',category:'daily',type:'spark',text:'Love today like you are aware that time is limited. Because it is.'},
{id:'d143',category:'daily',type:'spark',text:'What would you do today if you knew that how you showed up in this relationship is who you are?'},
{id:'d144',category:'daily',type:'spark',text:'Be interested in them today -- genuinely curious, not just politely attentive.'},
{id:'d145',category:'daily',type:'spark',text:'Name one thing you love about the way they love you. Tell them.'},
{id:'d146',category:'daily',type:'spark',text:'Do not wait for the perfect moment to be loving. Create the moment.'},
{id:'d147',category:'daily',type:'spark',text:'What is one thing you could stop doing today that would immediately improve the relationship?'},
{id:'d148',category:'daily',type:'spark',text:'Reach out to them during the day. A message, a call -- just to say: I\'m here.'},
{id:'d149',category:'daily',type:'spark',text:'Ask: "What would make you feel most loved this week?" Then do that.'},
{id:'d150',category:'daily',type:'spark',text:'Today, choose connection over being right. Just today. See how it feels.'},
{id:'him61',category:'him',type:'spark',text:'What has she been carrying that you have not fully seen? See it today.'},
{id:'him62',category:'him',type:'advice',text:'The man who learns to sit with his partner in their pain without trying to fix it becomes irreplaceable. You do not need answers. You need presence.',author:'Loving Better'},
{id:'him63',category:'him',type:'affirmation',text:'Your consistency is the most romantic thing you can offer her. Not grand gestures -- showing up the same way, every day.',author:'Loving Better'},
{id:'him64',category:'him',type:'spark',text:'What would she say is the best version of you? Work toward that version today.'},
{id:'him65',category:'him',type:'advice',text:'If you want her to be soft with you, be safe for her softness. Safety is created through consistency, gentleness, and follow-through. Build it.',author:'Loving Better'},
{id:'him66',category:'him',type:'affirmation',text:'The love you feel for her deserves to be expressed in a language she can feel. Find that language. Speak it.',author:'Loving Better'},
{id:'him67',category:'him',type:'spark',text:'What is the one thing she has asked you for consistently that you have not consistently provided? Start providing it.'},
{id:'him68',category:'him',type:'advice',text:'Ask her: "Is there anything I can do better this week?" Then listen. Really listen. Do not defend. Do not explain. Just hear what she says.',author:'Loving Better'},
{id:'him69',category:'him',type:'affirmation',text:'She chose you. In the middle of everything -- she chose you. Honour that with who you are choosing to become.',author:'Loving Better'},
{id:'him70',category:'him',type:'spark',text:'What would she be surprised to know you notice about her? Tell her today.'},
{id:'her61',category:'her',type:'spark',text:'What does the best version of yourself bring to this relationship? Bring that today.'},
{id:'her62',category:'her',type:'advice',text:'When you find yourself waiting to see what he will do before you decide what you will do -- that is not wisdom. That is reactivity. Choose your behaviour independently of his.',author:'Loving Better'},
{id:'her63',category:'her',type:'affirmation',text:'Your ability to name what you feel and what you need is a gift. Not every person can do that. Use it well.',author:'Loving Better'},
{id:'her64',category:'her',type:'spark',text:'What is one area where you have been growing that he may not have noticed? Tell him. Let him celebrate it.'},
{id:'her65',category:'her',type:'advice',text:'You can hold high standards and extend grace at the same time. These are not opposites. In fact, the person with the highest standards is the one most capable of grace -- because they understand what is possible.',author:'Loving Better'},
{id:'her66',category:'her',type:'affirmation',text:'The love you are capable of -- the full, open, unguarded version -- is one of the most extraordinary things available to the person you choose to give it to. Choose carefully. Give fully.',author:'Loving Better'},
{id:'her67',category:'her',type:'spark',text:'What do you know now about love that you wish you had known when this relationship began?'},
{id:'her68',category:'her',type:'advice',text:'Release the version of him you are most afraid he will stay as. See the version he is becoming. Those are different people. Respond to the one who is growing.',author:'Loving Better'},
{id:'her69',category:'her',type:'affirmation',text:'The fact that you stayed -- that you did not simply leave when it was hard -- is evidence of a depth of love that is rare. Do not let anyone minimise that, including yourself.',author:'Loving Better'},
{id:'her70',category:'her',type:'spark',text:'What would you tell a close friend who was in your exact situation right now? Tell yourself that.'},

{id:'l91',category:'love',type:'spark',text:'What does love look like as a daily habit, not a feeling? Practice the habit today.'},
{id:'l92',category:'love',type:'quote',text:'A relationship that is worth having is worth working for. Every single day.',author:'Loving Better'},
{id:'l93',category:'love',type:'advice',text:'The most loving thing you can sometimes do is nothing -- just sit beside someone in their struggle without trying to fix or advise. Presence without agenda is one of love\'s highest expressions.',author:'Loving Better'},
{id:'l94',category:'love',type:'spark',text:'What is one way you could make the ordinary day you are about to have into a loving one?'},
{id:'l95',category:'love',type:'quote',text:'Love that is only expressed in words is incomplete. Let your actions finish the sentence.',author:'Loving Better'},
{id:'l96',category:'love',type:'advice',text:'Do not be so focused on building toward the future of this relationship that you forget to inhabit its present. The present is where the love actually lives.',author:'Loving Better'},
{id:'l97',category:'love',type:'spark',text:'What is the most loving thing someone has ever done for you? Do something like it for them today.'},
{id:'l98',category:'love',type:'quote',text:'A love that does not grow is a love that is slowly shrinking. Keep growing it.',author:'Loving Better'},
{id:'l99',category:'love',type:'advice',text:'Love requires that you keep showing up even when you do not feel like it. Especially when you do not feel like it. That is what makes it love and not just preference.',author:'Loving Better'},
{id:'l100',category:'love',type:'spark',text:'Who is this person at their best? Treat them like that version today.'},
{id:'t61',category:'trust',type:'advice',text:'Become the person who does what they say, says what they mean, and means what they commit to. In a world of broken promises, that person is extraordinary.',author:'Loving Better'},
{id:'t62',category:'trust',type:'spark',text:'What is one small promise you can make and keep today -- something so specific it cannot be missed?'},
{id:'t63',category:'trust',type:'quote',text:'The partner who never gives you reason to wonder is the partner who is actively building your peace.',author:'Loving Better'},
{id:'t64',category:'trust',type:'advice',text:'Every time you choose honesty when a comfortable half-truth was available, you are making a deposit into the trust account. Those deposits are noticed, even when they are not acknowledged.',author:'Loving Better'},
{id:'t65',category:'trust',type:'spark',text:'Trust is demonstrated, not declared. Show it today through action.'},
{id:'t66',category:'trust',type:'quote',text:'When trust is present, the relationship is spacious. When it is absent, the relationship is claustrophobic.',author:'Loving Better'},
{id:'t67',category:'trust',type:'advice',text:'Do not ask for trust you have not yet earned. Ask instead for the opportunity to earn it, and then use that opportunity well.',author:'Loving Better'},
{id:'t68',category:'trust',type:'spark',text:'What is one area where your partner does not yet fully trust you? What would it take to change that?'},
{id:'t69',category:'trust',type:'quote',text:'A trustworthy partner is one of the rarest gifts in the world. Be that for someone.',author:'Loving Better'},
{id:'t70',category:'trust',type:'advice',text:'Check in regularly: "Is there anything I said I would do that I haven\'t done?" That question, asked voluntarily, is one of the most trust-building things you can say.',author:'Loving Better'},
{id:'h61',category:'healing',type:'advice',text:'The patterns that hurt you as a child do not disappear in adulthood. They change clothes. Learn to recognise them in their adult forms so you can respond consciously rather than reactively.',author:'Loving Better'},
{id:'h62',category:'healing',type:'spark',text:'What is one pattern from your family of origin that you are actively trying to break? Are you breaking it?'},
{id:'h63',category:'healing',type:'quote',text:'Healing is not a destination. It is a direction. Keep moving in it.',author:'Loving Better'},
{id:'h64',category:'healing',type:'advice',text:'Allow yourself to grieve what this relationship should have been in the seasons it was not. The grief is real. Let it move through you. Then build from where you are.',author:'Loving Better'},
{id:'h65',category:'healing',type:'spark',text:'What one word captures what you most need to release in order to move forward freely?'},
{id:'h66',category:'healing',type:'quote',text:'Every season of healing that you do the work in is a season your partner benefits from. Your healing is not just for you.',author:'Loving Better'},
{id:'h67',category:'healing',type:'advice',text:'When something from the past surfaces in the present, name it without shame: "This is touching something older for me." That kind of self-awareness changes the conversation.',author:'Loving Better'},
{id:'h68',category:'healing',type:'spark',text:'What would this relationship look like if both of you had done the work you know you need to do? Build toward that.'},
{id:'h69',category:'healing',type:'quote',text:'The couple that heals together creates something that broken couples never can: a shared knowledge of surviving the worst and choosing each other anyway.',author:'Loving Better'},
{id:'h70',category:'healing',type:'advice',text:'Healing does not mean you stop feeling the wound. It means the wound no longer makes your decisions for you.',author:'Loving Better'},
{id:'f41',category:'faith',type:'scripture',text:'Cast all your anxiety on him because he cares for you.',author:'1 Peter 5:7'},
{id:'f42',category:'faith',type:'advice',text:'In seasons of relational difficulty, do not pull away from your faith -- lean into it. The resources available to you through prayer, community, and scripture are precisely designed for this.',author:'Loving Better'},
{id:'f43',category:'faith',type:'scripture',text:'Rejoice always, pray continually, give thanks in all circumstances.',author:'1 Thessalonians 5:16-18'},
{id:'f44',category:'faith',type:'spark',text:'What scripture speaks most directly to where you are in this relationship right now? Hold it today.'},
{id:'f45',category:'faith',type:'quote',text:'A relationship surrendered to God is not a relationship without difficulty. It is a relationship with access to a strength greater than your own for navigating it.',author:'Loving Better'},
{id:'f46',category:'faith',type:'scripture',text:'The Lord is my shepherd, I lack nothing.',author:'Psalm 23:1'},
{id:'f47',category:'faith',type:'advice',text:'Let your faith be visible in how you love -- in your patience, your honesty, your willingness to forgive. The most powerful testimony is a relationship where faith is demonstrated, not just declared.',author:'Loving Better'},
{id:'f48',category:'faith',type:'scripture',text:'Whatever you do, work at it with all your heart, as working for the Lord.',author:'Colossians 3:23'},
{id:'f49',category:'faith',type:'spark',text:'What would it look like to approach this relationship as an act of worship -- as something you do for God as much as for each other?'},
{id:'f50',category:'faith',type:'quote',text:'The couple that makes God the third strand in their cord will find that it does not break easily.',author:'Loving Better'},
{id:'him71',category:'him',type:'advice',text:'Learn her love language and speak it fluently. Not occasionally -- consistently. The language that reaches her is the one worth learning regardless of whether it comes naturally to you.',author:'Loving Better'},
{id:'him72',category:'him',type:'spark',text:'What is she afraid of that she has never told you? Create a space safe enough for her to tell you.'},
{id:'him73',category:'him',type:'affirmation',text:'The man who pursues his partner with intention, not just in the beginning but for years -- that man is building something that most people only dream about.',author:'Loving Better'},
{id:'him74',category:'him',type:'advice',text:'Never stop asking her how she is. Not the obligatory "how are you" -- the real question, asked with time to hear the real answer.',author:'Loving Better'},
{id:'him75',category:'him',type:'spark',text:'What have you been learning about yourself through this relationship? Have you shared it with her?'},
{id:'him76',category:'him',type:'affirmation',text:'She is watching whether your actions and your words are the same thing. Let them be the same thing today.',author:'Loving Better'},
{id:'him77',category:'him',type:'advice',text:'Be the kind of man she does not have to manage. Where she can speak and be heard, feel pain and be held, need something and be given it without a negotiation. That man is the gift.',author:'Loving Better'},
{id:'him78',category:'him',type:'spark',text:'What is one way you can demonstrate today that you have been paying attention to her?'},
{id:'him79',category:'him',type:'affirmation',text:'Your presence -- real, full, unhurried presence -- is the most valuable thing you have to give her. Give it freely.',author:'Loving Better'},
{id:'him80',category:'him',type:'advice',text:'A relationship where she feels emotionally safe enough to be soft, to be vulnerable, to be exactly who she is -- that relationship was built by a man who consistently made it safe. Be that man.',author:'Loving Better'},
{id:'her71',category:'her',type:'advice',text:'The version of you that is fully loved, fully known, and fully alive is not hypothetical. She is waiting for a safe enough space to emerge. Help create that space -- and then step into it.',author:'Loving Better'},
{id:'her72',category:'her',type:'spark',text:'What is one thing you could do today that is purely about your own wellbeing -- not the relationship, not him, just you?'},
{id:'her73',category:'her',type:'affirmation',text:'You have survived seasons in this relationship that would have broken many people. You are stronger than you know, and wiser than you give yourself credit for.',author:'Loving Better'},
{id:'her74',category:'her',type:'advice',text:'Do not wait for him to change before you decide to be the person you want to be. Your character is your own responsibility. Lead with it.',author:'Loving Better'},
{id:'her75',category:'her',type:'spark',text:'What is one thing you admire about yourself in this relationship? Name it. You earned it.'},
{id:'her76',category:'her',type:'affirmation',text:'The capacity you have for honesty -- for saying the hard thing when it needs to be said -- is a profound gift. Channel it with love and it becomes one of the most powerful forces in a relationship.',author:'Loving Better'},
{id:'her77',category:'her',type:'advice',text:'Be as patient with his growth as you would want him to be with yours. Growth is rarely fast. What matters is the direction.',author:'Loving Better'},
{id:'her78',category:'her',type:'spark',text:'What does unconditional love ask of you today -- specifically, practically, in this relationship?'},
{id:'her79',category:'her',type:'affirmation',text:'Your joy matters. Your peace matters. Your flourishing matters -- not only to you but to the health of this relationship. Invest in it.',author:'Loving Better'},
{id:'her80',category:'her',type:'advice',text:'Give him the information he needs to love you well. Do not assume he knows what you need. Tell him -- specifically, kindly, without ultimatum. Then let him respond.',author:'Loving Better'},
{id:'d151',category:'daily',type:'spark',text:'What is one thing you are proud of about this relationship right now? Hold it.'},
{id:'d152',category:'daily',type:'spark',text:'Be gentle today -- with them and with yourself.'},
{id:'d153',category:'daily',type:'spark',text:'What is one thing they do for you that you have never said thank you for?'},
{id:'d154',category:'daily',type:'spark',text:'Today, choose the action that love would choose in the moment when it is hardest.'},
{id:'d155',category:'daily',type:'spark',text:'Send them one message today that is purely encouragement. Nothing else. Just encouragement.'},
{id:'d156',category:'daily',type:'spark',text:'What is one habit you could start today that would change this relationship in 90 days?'},
{id:'d157',category:'daily',type:'spark',text:'Speak about your partner kindly when they are not in the room. It always gets back.'},
{id:'d158',category:'daily',type:'spark',text:'What does your partner most need to hear today? Say it.'},
{id:'d159',category:'daily',type:'spark',text:'One full minute of undivided attention today. Just them. Just you. Present.'},
{id:'d160',category:'daily',type:'spark',text:'What would you do today if you were trying to win their heart all over again?'},
{id:'d161',category:'daily',type:'spark',text:'The relationship you want requires the person you are still becoming. Keep becoming.'},
{id:'d162',category:'daily',type:'spark',text:'What is one small sacrifice you can make today that would serve them?'},
{id:'d163',category:'daily',type:'spark',text:'Apologise first today -- even if you think you were more right than wrong.'},
{id:'d164',category:'daily',type:'spark',text:'Notice how they carry themselves today. What does their body language say they are carrying?'},
{id:'d165',category:'daily',type:'spark',text:'Give them grace today in one moment when grace is the harder choice.'},
{id:'d166',category:'daily',type:'spark',text:'Do not count what you give. Just give.'},
{id:'d167',category:'daily',type:'spark',text:'What is one thing from this relationship that you would miss unbearably if it were gone? Name it. Protect it.'},
{id:'d168',category:'daily',type:'spark',text:'Slow down today. Love at speed misses most of what matters.'},
{id:'d169',category:'daily',type:'spark',text:'What would you need to let go of to show up fully in this relationship today?'},
{id:'d170',category:'daily',type:'spark',text:'The love you build today is what you will live inside tomorrow. Build carefully.'},

{id:'d171',category:'daily',type:'spark',text:'What is one thing you know about love today that you did not know a year ago?'},
{id:'d172',category:'daily',type:'spark',text:'Be the reason they smile today. Actively. Deliberately.'},
{id:'d173',category:'daily',type:'spark',text:'What would you regret most about today if you could not change it tomorrow?'},
{id:'d174',category:'daily',type:'spark',text:'Choose kindness in the small moment today -- the one no one will notice except them.'},
{id:'d175',category:'daily',type:'spark',text:'Ask: "What is one thing I can do this week to love you better?" Then do it.'},
{id:'d176',category:'daily',type:'spark',text:'Look for what they are getting right today, not just what they are getting wrong.'},
{id:'d177',category:'daily',type:'spark',text:'The love you show today is the memory you are both building. Make it a good one.'},
{id:'d178',category:'daily',type:'spark',text:'Be someone they feel safe to fail in front of today.'},
{id:'d179',category:'daily',type:'spark',text:'What is the last thing you told them that was purely encouraging? Say something like it today.'},
{id:'d180',category:'daily',type:'spark',text:'Do one thing today that asks nothing in return.'},
{id:'g71',category:'growth',type:'spark',text:'What has this relationship taught you about yourself that nothing else could have?'},
{id:'g72',category:'growth',type:'quote',text:'The relationship that challenges you to grow is a greater gift than the one that lets you stay comfortable.',author:'Loving Better'},
{id:'g73',category:'growth',type:'advice',text:'The fact that you are still here, still trying, still wanting better -- that is already a form of growth. Do not disregard it.',author:'Loving Better'},
{id:'g74',category:'growth',type:'spark',text:'What is one conversation that would grow you both if you had it honestly and fully?'},
{id:'g75',category:'growth',type:'quote',text:'Growth in a relationship is not a straight line. It is a spiral -- returning to the same places but from a higher vantage point each time.',author:'Loving Better'},
{id:'fg71',category:'forgiveness',type:'advice',text:'The thing you cannot forgive is the thing that is slowly becoming your identity. Let it go. Your identity is larger than your wound.',author:'Loving Better'},
{id:'fg72',category:'forgiveness',type:'spark',text:'What would forgiveness make possible in this relationship that unforgiveness is currently preventing?'},
{id:'fg73',category:'forgiveness',type:'quote',text:'When you forgive, you are not doing it for them. You are doing it for the version of you that deserves to move freely.',author:'Loving Better'},
{id:'fg74',category:'forgiveness',type:'advice',text:'Teach yourself to forgive quickly. Not carelessly -- quickly. The longer you hold it, the more power it accumulates. Release it while it is still small.',author:'Loving Better'},
{id:'fg75',category:'forgiveness',type:'spark',text:'Say "I forgive you" without qualifying it today. No "but." No conditions. Just the forgiveness.'},
{id:'m91',category:'marriage',type:'advice',text:'The conversations you are having now -- about communication, about healing, about showing up -- are premarital counselling. Every honest talk is preparation. Keep having them.',author:'Loving Better'},
{id:'m92',category:'marriage',type:'spark',text:'What does faithfulness mean to you -- not just physically, but emotionally, attentionally, spiritually?'},
{id:'m93',category:'marriage',type:'quote',text:'A good marriage is not built in a day. It is built in ten thousand days, each one a choice.',author:'Loving Better'},
{id:'m94',category:'marriage',type:'advice',text:'The couple that discusses expectations openly before marriage spends far less time disappointed inside it. Talk about what you each expect -- from roles to romance to faith to finances.',author:'Loving Better'},
{id:'m95',category:'marriage',type:'spark',text:'What are you bringing into this marriage that you are proud of? What are you bringing that you are still working on?'},
{id:'t71',category:'trust',type:'advice',text:'Create the conditions for your partner to be honest with you by responding to honesty with gratitude rather than defensiveness. "Thank you for telling me that" changes what they are willing to tell you next time.',author:'Loving Better'},
{id:'t72',category:'trust',type:'spark',text:'What would need to be true for your partner to trust you fully? What is standing between you and that?'},
{id:'t73',category:'trust',type:'quote',text:'You cannot demand trust. You can only create the conditions under which it is reasonable.',author:'Loving Better'},
{id:'t74',category:'trust',type:'advice',text:'If there is something you have been withholding that your partner has a right to know -- tell them. The withholding costs more than the telling. It always does.',author:'Loving Better'},
{id:'t75',category:'trust',type:'spark',text:'Trust is also about being trusted. Are you the kind of partner your person can bring anything to?'},
{id:'h71',category:'healing',type:'advice',text:'Do not underestimate the healing power of being truly, unhurriedly listened to. Give that gift to your partner today. It costs nothing and changes everything.',author:'Loving Better'},
{id:'h72',category:'healing',type:'spark',text:'What part of yourself have you been hiding in this relationship? What would it take to show it?'},
{id:'h73',category:'healing',type:'quote',text:'Every day you choose to address something rather than avoid it is a day the relationship becomes safer.',author:'Loving Better'},
{id:'h74',category:'healing',type:'advice',text:'If you have been performing wellness -- saying you are fine when you are not, saying you have moved on when you have not -- stop. Real healing requires real honesty about where you actually are.',author:'Loving Better'},
{id:'h75',category:'healing',type:'spark',text:'What does it feel like in your body when you are at peace in this relationship? Remember that feeling. Work toward it.'},
{id:'f51',category:'faith',type:'scripture',text:'Jesus replied: Love the Lord your God with all your heart and with all your soul and with all your mind. This is the first and greatest commandment. And the second is like it: Love your neighbour as yourself.',author:'Matthew 22:37-39'},
{id:'f52',category:'faith',type:'advice',text:'Bring God into your arguments. Not as a weapon -- "God is on my side" -- but as a source of peace: "God, help us navigate this." That prayer changes the atmosphere of a hard conversation.',author:'Loving Better'},
{id:'f53',category:'faith',type:'scripture',text:'Where two or three gather in my name, there am I with them.',author:'Matthew 18:20'},
{id:'f54',category:'faith',type:'spark',text:'What would it mean to truly invite God into the daily texture of this relationship, not just the crisis moments?'},
{id:'f55',category:'faith',type:'quote',text:'A relationship where both people are surrendered to God is a relationship with access to a love that does not depend on how either person is feeling on any given day.',author:'Loving Better'},
{id:'him81',category:'him',type:'advice',text:'What she needs from you most is not a better version of what you already give. It is the thing you have been withholding -- your full emotional presence, your words, your honest inner world. Give that.',author:'Loving Better'},
{id:'him82',category:'him',type:'spark',text:'What is one thing she has said she needs from you more than once that you have not yet consistently given?'},
{id:'him83',category:'him',type:'affirmation',text:'The work you are doing on yourself -- even imperfectly, even slowly -- is noticed. Keep doing it.',author:'Loving Better'},
{id:'him84',category:'him',type:'advice',text:'Love her the way you would want your daughter to be loved. That standard will change how you show up.',author:'Loving Better'},
{id:'him85',category:'him',type:'spark',text:'What kind of man does this relationship need you to become? Begin becoming him today.'},
{id:'her81',category:'her',type:'advice',text:'You are allowed to have needs. You are allowed to name them. You are allowed to be disappointed when they are not met. You are also allowed to believe they can be met -- by the right person, at the right time.',author:'Loving Better'},
{id:'her82',category:'her',type:'spark',text:'What would full trust in this person -- in who they are choosing to become -- make possible for you?'},
{id:'her83',category:'her',type:'affirmation',text:'The love you carry for him -- even through the difficult seasons, even while you were hurting -- that love is extraordinary. Do not let anyone tell you otherwise.',author:'Loving Better'},
{id:'her84',category:'her',type:'advice',text:'Your healing and the relationship\'s healing are not separate things. As you become more whole, what you are able to give -- and receive -- expands. Do your own work. It matters.',author:'Loving Better'},
{id:'her85',category:'her',type:'spark',text:'What is the most generous thing you could believe about him today? Believe it. Let it be true until proven otherwise.'},

];

// ── Helpers ───────────────────────────────────────────────────────────────────
export function getWisdomByCategory(cat) {
  if (cat === 'all') return WISDOM;
  return WISDOM.filter(w => w.category === cat);
}

export function getDailyWisdom() {
  const day = Math.floor(Date.now() / 86400000);
  return WISDOM[day % WISDOM.length];
}

export function getRandomWisdom(excluding = []) {
  const pool = WISDOM.filter(w => !excluding.includes(w.id));
  if (!pool.length) return WISDOM[Math.floor(Math.random() * WISDOM.length)];
  return pool[Math.floor(Math.random() * pool.length)];
}

export function getTypeColor(type) {
  return {
    quote:       { bg:'#FDE8EC', border:'#C0556A', label:'Quote',       labelColor:'#C0556A' },
    advice:      { bg:'#FFF8F0', border:'#B8860B', label:'Advice',      labelColor:'#B8860B' },
    scripture:   { bg:'#EEF5F0', border:'#5A7A6E', label:'Scripture',   labelColor:'#5A7A6E' },
    spark:       { bg:'#F0EEFF', border:'#6B5BD2', label:'Daily Spark', labelColor:'#6B5BD2' },
    affirmation: { bg:'#FFF0F5', border:'#D4758A', label:'Affirmation', labelColor:'#D4758A' },
  }[type] || { bg:'#F5F5F5', border:'#999', label:type, labelColor:'#666' };
}
